window.KJV1769_STRONG_BOOKS["Heb"] = {"osis":"Heb","book":"히브리서","verses":{"1:1":{"text":"God, who at sundry times and in divers manners spake in time past unto the fathers by the prophets,","words":[["G2316","God",0,3],["G4181","who at sundry times",5,24],["G2532","and",25,28],["G4187","in divers manners",29,46],["G2980","spake",47,52],["G3819","in time past",53,65],["G3962","unto the fathers",66,82],["G1722","by",83,85],["G4396","the prophets",86,98]]},"1:2":{"text":"Hath in these last days spoken unto us by his Son, whom he hath appointed heir of all things, by whom also he made the worlds;","words":[["G2980","Hath",0,4],["G1909","in",5,7],["G5130","these",8,13],["G2078","last",14,18],["G2250","days",19,23],["G2980","spoken",24,30],["G2254","unto us",31,38],["G1722","by",39,41],["G5207","his Son",42,49],["G3739","whom",51,55],["G5087","he hath appointed",56,73],["G2818","heir",74,78],["G3956","of all things",79,92],["G1223","by",94,96],["G3739","whom",97,101],["G2532","also",102,106],["G4160","he made",107,114],["G0165","the worlds",115,125]]},"1:3":{"text":"Who being the brightness of his glory, and the express image of his person, and upholding all things by the word of his power, when he had by himself purged our sins, sat down on the right hand of the Majesty on high;","words":[["G3739","Who",0,3],["G5607","being",4,9],["G0541","the brightness",10,24],["G1391","of his glory",25,37],["G2532","and",39,42],["G5481","the express image",43,60],["G0846","of his",61,67],["G5287","person",68,74],["G5037","and",76,79],["G5342","upholding",80,89],["G3956","all things",90,100],["G4487","by the word",101,112],["G0846","of his",113,119],["G1411","power",120,125],["G4160","when he had",127,138],["G2512","when he had",127,138],["G1223","by",139,141],["G1438","himself",142,149],["G4160","purged",150,156],["G2512","purged",150,156],["G2257","our",157,160],["G0266","sins",161,165],["G2523","sat down",167,175],["G1722","on",176,178],["G1188","the right hand",179,193],["G3172","of the Majesty",194,208],["G1722","on",209,211],["G5308","high",212,216]]},"1:4":{"text":"Being made so much better than the angels, as he hath by inheritance obtained a more excellent name than they.","words":[["G1096","Being made",0,10],["G5118","so much",11,18],["G2909","better than",19,30],["G0032","the angels",31,41],["G3745","as",43,45],["G2816","he hath by inheritance obtained",46,77],["G1313","a more excellent",78,94],["G3686","name",95,99],["G3844","than",100,104],["G0846","they",105,109]]},"1:5":{"text":"For unto which of the angels said he at any time, Thou art my Son, this day have I begotten thee? And again, I will be to him a Father, and he shall be to me a Son?","words":[["G1063","For",0,3],["G5101","unto which",4,14],["G0032","of the angels",15,28],["G2036","said he",29,36],["G4218","at any time",37,48],["G4771","Thou",50,54],["G1488","art",55,58],["G3450","my",59,61],["G5207","Son",62,65],["G4594","this day",67,75],["G1080","have",76,80],["G1473","I",81,82],["G1080","begotten",83,91],["G4571","thee",92,96],["G2532","And",98,101],["G3825","again",102,107],["G1473","I",109,110],["G2071","will be",111,118],["G1519","to",119,121],["G0846","him",122,125],["G3962","a Father",126,134],["G2532","and",136,139],["G0846","he",140,142],["G2071","shall be",143,151],["G1519","to",152,154],["G3427","me",155,157],["G5207","a Son",158,163]]},"1:6":{"text":"And again, when he bringeth in the firstbegotten into the world, he saith, And let all the angels of God worship him.","words":[["G1161","And",0,3],["G3825","again",4,9],["G3752","when",11,15],["G1521","he bringeth in",16,30],["G4416","the firstbegotten",31,48],["G1519","into",49,53],["G3625","the world",54,63],["G3004","he saith",65,73],["G2532","And",75,78],["G4352","let",79,82],["G3956","all",83,86],["G0032","the angels",87,97],["G2316","of God",98,104],["G4352","worship",105,112],["G0846","him",113,116]]},"1:7":{"text":"And of the angels he saith, Who maketh his angels spirits, and his ministers a flame of fire.","words":[["G2532","And",0,3],["G4314","of",4,6],["G3303","of",4,6],["G0032","the angels",7,17],["G3004","he saith",18,26],["G4160","Who maketh",28,38],["G0846","his",39,42],["G0032","angels",43,49],["G4151","spirits",50,57],["G2532","and",59,62],["G0846","his",63,66],["G3011","ministers",67,76],["G5395","a flame",77,84],["G4442","of fire",85,92]]},"1:8":{"text":"But unto the Son he saith, Thy throne, O God, is for ever and ever: a sceptre of righteousness is the sceptre of thy kingdom.","words":[["G1161","But",0,3],["G4314","unto",4,8],["G5207","the Son",9,16],["G4675","he saith, Thy",17,30],["G2362","throne",31,37],["G2316","O God",39,44],["G1519","is for",46,52],["G0165","ever",53,57],["G0165","and ever",58,66],["G4464","a sceptre",68,77],["G2118","of righteousness",78,94],["G4464","is the sceptre",95,109],["G4675","of thy",110,116],["G0932","kingdom",117,124]]},"1:9":{"text":"Thou hast loved righteousness, and hated iniquity; therefore God, even thy God, hath anointed thee with the oil of gladness above thy fellows.","words":[["G0025","Thou hast loved",0,15],["G1343","righteousness",16,29],["G2532","and",31,34],["G3404","hated",35,40],["G0458","iniquity",41,49],["G1223","therefore",51,60],["G5124","therefore",51,60],["G2316","God",61,64],["G4675","even thy",66,74],["G2316","God",75,78],["G5548","hath anointed",80,93],["G4571","thee",94,98],["G1637","with the oil",99,111],["G0020","of gladness",112,123],["G3844","above",124,129],["G4675","thy",130,133],["G3353","fellows",134,141]]},"1:10":{"text":"And, Thou, Lord, in the beginning hast laid the foundation of the earth; and the heavens are the works of thine hands:","words":[["G2532","And",0,3],["G4771","Thou",5,9],["G2962","Lord",11,15],["G2596","in",17,19],["G0746","the beginning",20,33],["G2311","hast laid the foundation",34,58],["G1093","of the earth",59,71],["G2532","and",73,76],["G3772","the heavens",77,88],["G1526","are",89,92],["G2041","the works",93,102],["G4675","of thine",103,111],["G5495","hands",112,117]]},"1:11":{"text":"They shall perish; but thou remainest; and they all shall wax old as doth a garment;","words":[["G0846","They",0,4],["G0622","shall perish",5,17],["G1161","but",19,22],["G4771","thou",23,27],["G1265","remainest",28,37],["G2532","and",39,42],["G3956","they all",43,51],["G3822","shall wax old",52,65],["G5613","as",66,68],["G2440","doth a garment",69,83]]},"1:12":{"text":"And as a vesture shalt thou fold them up, and they shall be changed: but thou art the same, and thy years shall not fail.","words":[["G2532","And",0,3],["G5616","as",4,6],["G4018","a vesture",7,16],["G1667","shalt thou fold",17,32],["G0846","them",33,37],["G1667","up",38,40],["G2532","and",42,45],["G0236","they shall be changed",46,67],["G1161","but",69,72],["G4771","thou",73,77],["G1488","art",78,81],["G0846","the same",82,90],["G2532","and",92,95],["G4675","thy",96,99],["G2094","years",100,105],["G1587","shall",106,111],["G3756","not",112,115],["G1587","fail",116,120]]},"1:13":{"text":"But to which of the angels said he at any time, Sit on my right hand, until I make thine enemies thy footstool?","words":[["G1161","But",0,3],["G4314","to",4,6],["G5101","which",7,12],["G0032","of the angels",13,26],["G2046","said he",27,34],["G4218","at any time",35,46],["G2521","Sit",48,51],["G1537","on",52,54],["G3450","my",55,57],["G1188","right hand",58,68],["G0302","until",70,75],["G2193","until",70,75],["G5087","I make",76,82],["G4675","thine",83,88],["G2190","enemies",89,96],["G4675","thy",97,100],["G5286","footstool",101,110],["G4228","footstool",101,110]]},"1:14":{"text":"Are they not all ministering spirits, sent forth to minister for them who shall be heirs of salvation?","words":[["G1526","Are they",0,8],["G3780","not",9,12],["G3956","all",13,16],["G3010","ministering",17,28],["G4151","spirits",29,36],["G0649","sent forth",38,48],["G1519","to",49,51],["G1248","minister",52,60],["G1223","for",61,64],["G3195","them who shall",65,79],["G2816","be heirs of",80,91],["G4991","salvation",92,101]]},"2:1":{"text":"Therefore we ought to give the more earnest heed to the things which we have heard, lest at any time we should let them slip.","words":[["G1223","Therefore",0,9],["G5124","Therefore",0,9],["G2248","we",10,12],["G1163","ought",13,18],["G4056","to give the more earnest",19,43],["G4337","heed",44,48],["G0191","to the things which we have heard",49,82],["G3379","lest at any time",84,100],["G3901","we should let them slip",101,124]]},"2:2":{"text":"For if the word spoken by angels was stedfast, and every transgression and disobedience received a just recompence of reward;","words":[["G1063","For",0,3],["G1487","if",4,6],["G3056","the word",7,15],["G2980","spoken",16,22],["G1223","by",23,25],["G0032","angels",26,32],["G1096","was",33,36],["G0949","stedfast",37,45],["G2532","and",47,50],["G3956","every",51,56],["G3847","transgression",57,70],["G2532","and",71,74],["G3876","disobedience",75,87],["G2983","received",88,96],["G1738","a just",97,103],["G3405","recompence of reward",104,124]]},"2:3":{"text":"How shall we escape, if we neglect so great salvation; which at the first began to be spoken by the Lord, and was confirmed unto us by them that heard him;","words":[["G4459","How",0,3],["G2249","shall we",4,12],["G1628","escape",13,19],["G0272","if we neglect",21,34],["G5082","so great",35,43],["G4991","salvation",44,53],["G3748","which",55,60],["G0746","at the first",61,73],["G2983","began",74,79],["G2980","to be spoken",80,92],["G1223","by",93,95],["G2962","the Lord",96,104],["G0950","and was confirmed",106,123],["G1519","unto",124,128],["G2248","us",129,131],["G5259","by",132,134],["G0191","them that heard",135,150]]},"2:4":{"text":"God also bearing them witness, both with signs and wonders, and with divers miracles, and gifts of the Holy Ghost, according to his own will?","words":[["G2316","God",0,3],["G4901","also bearing them witness",4,29],["G5037","both",31,35],["G4592","with signs",36,46],["G2532","and",47,50],["G5059","wonders",51,58],["G2532","and",60,63],["G4164","with divers",64,75],["G1411","miracles",76,84],["G2532","and",86,89],["G3311","gifts",90,95],["G0040","of the Holy",96,107],["G4151","Ghost",108,113],["G2596","according to",115,127],["G0846","his own",128,135],["G2308","will",136,140]]},"2:5":{"text":"For unto the angels hath he not put in subjection the world to come, whereof we speak.","words":[["G1063","For",0,3],["G0032","unto the angels",4,19],["G5293","hath he",20,27],["G3756","not",28,31],["G5293","put in subjection",32,49],["G3625","the world",50,59],["G3195","to come",60,67],["G4012","whereof",69,76],["G3739","whereof",69,76],["G2980","we speak",77,85]]},"2:6":{"text":"But one in a certain place testified, saying, What is man, that thou art mindful of him? or the son of man, that thou visitest him?","words":[["G1161","But",0,3],["G5100","one",4,7],["G4225","in a certain place",8,26],["G1263","testified",27,36],["G3004","saying",38,44],["G5101","What",46,50],["G2076","is",51,53],["G0444","man",54,57],["G3754","that",59,63],["G3403","thou art mindful",64,80],["G0846","of him",81,87],["G2228","or",89,91],["G5207","the son",92,99],["G0444","of man",100,106],["G3754","that",108,112],["G1980","thou visitest",113,126],["G0846","him",127,130]]},"2:7":{"text":"Thou madest him a little lower than the angels; thou crownedst him with glory and honour, and didst set him over the works of thy hands:","words":[["G1642","Thou madest",0,11],["G0846","him",12,15],["G1024","a little",16,24],["G5100","a little",16,24],["G1642","lower",25,30],["G3844","than",31,35],["G0032","the angels",36,46],["G4737","thou crownedst",48,62],["G0846","him",63,66],["G1391","with glory",67,77],["G2532","and",78,81],["G5092","honour",82,88],["G2532","and",90,93],["G2525","didst set",94,103],["G0846","him",104,107],["G1909","over",108,112],["G2041","the works",113,122],["G4675","of thy",123,129],["G5495","hands",130,135]]},"2:8":{"text":"Thou hast put all things in subjection under his feet. For in that he put all in subjection under him, he left nothing that is not put under him. But now we see not yet all things put under him.","words":[["G5293","Thou hast put",0,13],["G3956","all things",14,24],["G5293","in subjection",25,38],["G5270","under",39,44],["G0846","his",45,48],["G4228","feet",49,53],["G1063","For",55,58],["G1722","in",59,61],["G5293","that he put",62,73],["G3956","all",74,77],["G5293","in subjection under",78,97],["G0846","him",98,101],["G0863","he left",103,110],["G3762","nothing that is not",111,130],["G0506","put under",131,140],["G0846","him",141,144],["G1161","But",146,149],["G3568","now",150,153],["G3708","we see",154,160],["G3768","not yet",161,168],["G3956","all things",169,179],["G5293","put under",180,189],["G0846","him",190,193]]},"2:9":{"text":"But we see Jesus, who was made a little lower than the angels for the suffering of death, crowned with glory and honour; that he by the grace of God should taste death for every man.","words":[["G1161","But",0,3],["G0991","we see",4,10],["G2424","Jesus",11,16],["G3588","who",18,21],["G1642","was made",22,30],["G1024","a little",31,39],["G5100","a little",31,39],["G1642","lower",40,45],["G3844","than",46,50],["G0032","the angels",51,61],["G1223","for",62,65],["G3804","the suffering",66,79],["G2288","of death",80,88],["G4737","crowned",90,97],["G1391","with glory",98,108],["G2532","and",109,112],["G5092","honour",113,119],["G3704","that",121,125],["G1089","he",126,128],["G5485","by the grace",129,141],["G2316","of God",142,148],["G1089","should taste",149,161],["G2288","death",162,167],["G5228","for",168,171],["G3956","every man",172,181]]},"2:10":{"text":"For it became him, for whom are all things, and by whom are all things, in bringing many sons unto glory, to make the captain of their salvation perfect through sufferings.","words":[["G1063","For",0,3],["G4241","it became",4,13],["G0846","him",14,17],["G1223","for",19,22],["G3739","whom",23,27],["G3956","are all things",28,42],["G2532","and",44,47],["G1223","by",48,50],["G3739","whom",51,55],["G3956","are all things",56,70],["G0071","in bringing",72,83],["G4183","many",84,88],["G5207","sons",89,93],["G1519","unto",94,98],["G1391","glory",99,104],["G5048","to make",106,113],["G0747","the captain",114,125],["G0846","of their",126,134],["G4991","salvation",135,144],["G5048","perfect",145,152],["G1223","through",153,160],["G3804","sufferings",161,171]]},"2:11":{"text":"For both he that sanctifieth and they who are sanctified are all of one: for which cause he is not ashamed to call them brethren,","words":[["G1063","For",0,3],["G5037","both",4,8],["G0037","he that sanctifieth",9,28],["G2532","and",29,32],["G0037","they who are sanctified",33,56],["G3956","are all",57,64],["G1537","of",65,67],["G1520","one",68,71],["G1223","for",73,76],["G3739","which",77,82],["G0156","cause",83,88],["G1870","he is",89,94],["G3756","not",95,98],["G1870","ashamed",99,106],["G2564","to call",107,114],["G0846","them",115,119],["G0080","brethren",120,128]]},"2:12":{"text":"Saying, I will declare thy name unto my brethren, in the midst of the church will I sing praise unto thee.","words":[["G3004","Saying",0,6],["G0518","I will declare",8,22],["G4675","thy",23,26],["G3686","name",27,31],["G3450","unto my",32,39],["G0080","brethren",40,48],["G1722","in",50,52],["G3319","the midst",53,62],["G1577","of the church",63,76],["G5214","will I sing praise",77,95],["G4571","unto thee",96,105]]},"2:13":{"text":"And again, I will put my trust in him. And again, Behold I and the children which God hath given me.","words":[["G2532","And",0,3],["G3825","again",4,9],["G1473","I",11,12],["G2071","will",13,17],["G3982","put my trust",18,30],["G1909","in",31,33],["G0846","him",34,37],["G2532","And",39,42],["G3825","again",43,48],["G2400","Behold",50,56],["G1473","I",57,58],["G2532","and",59,62],["G3813","the children",63,75],["G3739","which",76,81],["G2316","God",82,85],["G1325","hath given",86,96],["G3427","me",97,99]]},"2:14":{"text":"Forasmuch then as the children are partakers of flesh and blood, he also himself likewise took part of the same; that through death he might destroy him that had the power of death, that is, the devil;","words":[["G1893","Forasmuch",0,9],["G3767","then",10,14],["G3813","as the children",15,30],["G2841","are partakers",31,44],["G4561","of flesh",45,53],["G2532","and",54,57],["G0129","blood",58,63],["G3348","he",65,67],["G2532","also",68,72],["G0846","himself",73,80],["G3898","likewise",81,89],["G3348","took part",90,99],["G0846","of the same",100,111],["G2443","that",113,117],["G1223","through",118,125],["G2288","death",126,131],["G2673","he might destroy",132,148],["G2192","him that had",149,161],["G2904","the power",162,171],["G2288","of death",172,180],["G5123","that is",182,189],["G1228","the devil",191,200]]},"2:15":{"text":"And deliver them who through fear of death were all their lifetime subject to bondage.","words":[["G2532","And",0,3],["G0525","deliver",4,11],["G5128","them",12,16],["G3745","who",17,20],["G1223","through",21,28],["G5401","fear",29,33],["G2288","of death",34,42],["G2258","were",43,47],["G3956","all",48,51],["G2198","their lifetime",52,66],["G1777","subject",67,74],["G1397","to bondage",75,85]]},"2:16":{"text":"For verily he took not on him the nature of angels; but he took on him the seed of Abraham.","words":[["G1063","For",0,3],["G1222","verily",4,10],["G1949","he took",11,18],["G3756","not",19,22],["G1949","on",23,25],["G0032","him the nature of angels",26,50],["G0235","but",52,55],["G1949","he took on",56,66],["G4690","him the seed",67,79],["G0011","of Abraham",80,90]]},"2:17":{"text":"Wherefore in all things it behoved him to be made like unto his brethren, that he might be a merciful and faithful high priest in things pertaining to God, to make reconciliation for the sins of the people.","words":[["G3606","Wherefore",0,9],["G2596","in",10,12],["G3956","all things",13,23],["G3784","it behoved him",24,38],["G3666","to be made like",39,54],["G0080","unto his brethren",55,72],["G2443","that",74,78],["G1096","he might be",79,90],["G1655","a merciful",91,101],["G2532","and",102,105],["G4103","faithful",106,114],["G0749","high priest",115,126],["G4314","in things pertaining to",127,150],["G2316","God",151,154],["G1519","to",156,158],["G2433","make reconciliation for",159,182],["G0266","the sins",183,191],["G2992","of the people",192,205]]},"2:18":{"text":"For in that he himself hath suffered being tempted, he is able to succour them that are tempted.","words":[["G1063","For",0,3],["G1722","in",4,6],["G3739","that",7,11],["G3958","he",12,14],["G0846","himself",15,22],["G3958","hath suffered",23,36],["G3985","being tempted",37,50],["G1410","he is able",52,62],["G0997","to succour",63,73],["G3985","them that are tempted",74,95]]},"3:1":{"text":"Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus;","words":[["G3606","Wherefore",0,9],["G0040","holy",11,15],["G0080","brethren",16,24],["G3353","partakers",26,35],["G2032","of the heavenly",36,51],["G2821","calling",52,59],["G2657","consider",61,69],["G0652","the Apostle",70,81],["G2532","and",82,85],["G0749","High Priest",86,97],["G2257","of our",98,104],["G3671","profession",105,115],["G5547","Christ",117,123],["G2424","Jesus",124,129]]},"3:2":{"text":"Who was faithful to him that appointed him, as also Moses was faithful in all his house.","words":[["G5607","Who was",0,7],["G4103","faithful",8,16],["G4160","to him that appointed",17,38],["G0846","him",39,42],["G5613","as",44,46],["G2532","also",47,51],["G3475","Moses",52,57],["G1722","was faithful in",58,73],["G3650","all",74,77],["G0846","his",78,81],["G3624","house",82,87]]},"3:3":{"text":"For this man was counted worthy of more glory than Moses, inasmuch as he who hath builded the house hath more honour than the house.","words":[["G1063","For",0,3],["G3778","this",4,8],["G0515","man was counted worthy",9,31],["G4119","of more",32,39],["G1391","glory",40,45],["G3844","than",46,50],["G3475","Moses",51,56],["G2596","inasmuch as",58,69],["G3745","inasmuch as",58,69],["G2680","he who hath builded",70,89],["G3624","the house",90,99],["G4119","hath more",100,109],["G5092","honour",110,116],["G2192","than",117,121],["G0846","the house",122,131]]},"3:4":{"text":"For every house is builded by some man; but he that built all things is God.","words":[["G1063","For",0,3],["G3956","every",4,9],["G3624","house",10,15],["G2680","is builded",16,26],["G5259","by",27,29],["G5100","some",30,34],["G1161","man; but",35,43],["G2680","he that built",44,57],["G3956","all things",58,68],["G2316","is God",69,75]]},"3:5":{"text":"And Moses verily was faithful in all his house, as a servant, for a testimony of those things which were to be spoken after;","words":[["G2532","And",0,3],["G3475","Moses",4,9],["G3303","verily",10,16],["G4103","was faithful",17,29],["G1722","in",30,32],["G3650","all",33,36],["G0846","his",37,40],["G3624","house",41,46],["G5613","as",48,50],["G2324","a servant",51,60],["G1519","for",62,65],["G3142","a testimony",66,77],["G2980","of those things which were to be spoken after",78,123]]},"3:6":{"text":"But Christ as a son over his own house; whose house are we, if we hold fast the confidence and the rejoicing of the hope firm unto the end.","words":[["G1161","But",0,3],["G5547","Christ",4,10],["G5613","as",11,13],["G5207","a son",14,19],["G1909","over",20,24],["G0846","his own",25,32],["G3624","house",33,38],["G3739","whose",40,45],["G3624","house",46,51],["G2070","are",52,55],["G2249","we",56,58],["G1437","if",60,62],["G4007","if",60,62],["G2722","we hold fast",63,75],["G3954","the confidence",76,90],["G2532","and",91,94],["G2745","the rejoicing",95,108],["G1680","of the hope",109,120],["G0949","firm",121,125],["G3360","unto",126,130],["G5056","the end",131,138]]},"3:7":{"text":"Wherefore (as the Holy Ghost saith, To day if ye will hear his voice,","words":[["G1352","Wherefore",0,9],["G2531","(as",10,13],["G0040","the Holy",14,22],["G4151","Ghost",23,28],["G3004","saith",29,34],["G4594","To day",36,42],["G1437","if",43,45],["G0191","ye will hear",46,58],["G0846","his",59,62],["G5456","voice",63,68]]},"3:8":{"text":"Harden not your hearts, as in the provocation, in the day of temptation in the wilderness:","words":[["G4645","Harden",0,6],["G3361","not",7,10],["G5216","your",11,15],["G2588","hearts",16,22],["G5613","as",24,26],["G1722","in",27,29],["G3894","the provocation",30,45],["G2596","in",47,49],["G2250","the day",50,57],["G3986","of temptation",58,71],["G1722","in",72,74],["G2048","the wilderness",75,89]]},"3:9":{"text":"When your fathers tempted me, proved me, and saw my works forty years.","words":[["G3757","When",0,4],["G5216","your",5,9],["G3962","fathers",10,17],["G3985","tempted",18,25],["G3165","me",26,28],["G1381","proved",30,36],["G3165","me",37,39],["G2532","and",41,44],["G1492","saw",45,48],["G3450","my",49,51],["G2041","works",52,57],["G5062","forty",58,63],["G2094","years",64,69]]},"3:10":{"text":"Wherefore I was grieved with that generation, and said, They do alway err in their heart; and they have not known my ways.","words":[["G1352","Wherefore",0,9],["G4360","I was grieved",10,23],["G1565","with that",24,33],["G1074","generation",34,44],["G2532","and",46,49],["G2036","said",50,54],["G4105","They do",56,63],["G0104","alway",64,69],["G4105","err",70,73],["G2588","in their heart",74,88],["G1161","and",90,93],["G0846","they",94,98],["G1097","have",99,103],["G3756","not",104,107],["G1097","known",108,113],["G3450","my",114,116],["G3598","ways",117,121]]},"3:11":{"text":"So I sware in my wrath, They shall not enter into my rest.)","words":[["G5613","So",0,2],["G3660","I sware",3,10],["G1722","in",11,13],["G3450","my",14,16],["G3709","wrath",17,22],["G1525","They shall",24,34],["G1487","not",35,38],["G1525","enter",39,44],["G1519","into",45,49],["G3450","my",50,52],["G2663","rest",53,57]]},"3:12":{"text":"Take heed, brethren, lest there be in any of you an evil heart of unbelief, in departing from the living God.","words":[["G0991","Take heed",0,9],["G0080","brethren",11,19],["G3379","lest",21,25],["G2071","there be",26,34],["G1722","in",35,37],["G5100","any",38,41],["G5216","of you",42,48],["G4190","an evil",49,56],["G2588","heart",57,62],["G0570","of unbelief",63,74],["G1722","in",76,78],["G0868","departing",79,88],["G0575","from",89,93],["G2198","the living",94,104],["G2316","God",105,108]]},"3:13":{"text":"But exhort one another daily, while it is called To day; lest any of you be hardened through the deceitfulness of sin.","words":[["G0235","But",0,3],["G3870","exhort",4,10],["G1438","one another",11,22],["G2596","daily",23,28],["G1538","daily",23,28],["G2250","daily",23,28],["G0891","while",30,35],["G3739","while",30,35],["G2564","it is called",36,48],["G4594","To day",49,55],["G3363","lest",57,61],["G5100","any",62,65],["G1537","of",66,68],["G5216","you",69,72],["G4645","be hardened",73,84],["G0539","through the deceitfulness",85,110],["G0266","of sin",111,117]]},"3:14":{"text":"For we are made partakers of Christ, if we hold the beginning of our confidence stedfast unto the end;","words":[["G1063","For",0,3],["G1096","we are made",4,15],["G3353","partakers",16,25],["G5547","of Christ",26,35],["G1437","if",37,39],["G4007","if",37,39],["G2722","we hold",40,47],["G0746","the beginning",48,61],["G5287","of our confidence",62,79],["G0949","stedfast",80,88],["G3360","unto",89,93],["G5056","the end",94,101]]},"3:15":{"text":"While it is said, To day if ye will hear his voice, harden not your hearts, as in the provocation.","words":[["G1722","While",0,5],["G3004","it is said",6,16],["G4594","To day",18,24],["G1437","if",25,27],["G0191","ye will hear",28,40],["G0846","his",41,44],["G5456","voice",45,50],["G4645","harden",52,58],["G3361","not",59,62],["G5216","your",63,67],["G2588","hearts",68,74],["G5613","as",76,78],["G1722","in",79,81],["G3894","the provocation",82,97]]},"3:16":{"text":"For some, when they had heard, did provoke: howbeit not all that came out of Egypt by Moses.","words":[["G1063","For",0,3],["G5100","some",4,8],["G0191","when they had heard",10,29],["G3893","did provoke",31,42],["G0235","howbeit",44,51],["G3756","not",52,55],["G3956","all",56,59],["G1831","that came",60,69],["G1537","out of",70,76],["G0125","Egypt",77,82],["G1223","by",83,85],["G3475","Moses",86,91]]},"3:17":{"text":"But with whom was he grieved forty years? was it not with them that had sinned, whose carcases fell in the wilderness?","words":[["G1161","But",0,3],["G5101","with whom",4,13],["G4360","was he grieved",14,28],["G5062","forty",29,34],["G2094","years",35,40],["G3780","was it not",42,52],["G0264","with them that had sinned",53,78],["G3739","whose",80,85],["G2966","carcases",86,94],["G4098","fell",95,99],["G1722","in",100,102],["G2048","the wilderness",103,117]]},"3:18":{"text":"And to whom sware he that they should not enter into his rest, but to them that believed not?","words":[["G1161","And",0,3],["G5101","to whom",4,11],["G3660","sware he",12,20],["G1525","that they should",21,37],["G3361","not",38,41],["G1525","enter",42,47],["G1519","into",48,52],["G0846","his",53,56],["G2663","rest",57,61],["G1508","but",63,66],["G0544","to them that believed not",67,92]]},"3:19":{"text":"So we see that they could not enter in because of unbelief.","words":[["G2532","So",0,2],["G0991","we see",3,9],["G3754","that",10,14],["G1410","they could",15,25],["G3756","not",26,29],["G1525","enter in",30,38],["G1223","because",39,46],["G0570","of unbelief",47,58]]},"4:1":{"text":"Let us therefore fear, lest, a promise being left us of entering into his rest, any of you should seem to come short of it.","words":[["G5399","Let us",0,6],["G3767","therefore",7,16],["G5399","fear",17,21],["G3379","lest",23,27],["G1860","a promise",29,38],["G2641","being left",39,49],["G1525","us of entering",50,64],["G1519","into",65,69],["G0846","his",70,73],["G2663","rest",74,78],["G5100","any",80,83],["G1537","of",84,86],["G5216","you",87,90],["G1380","should seem",91,102],["G5302","to come short of it",103,122]]},"4:2":{"text":"For unto us was the gospel preached, as well as unto them: but the word preached did not profit them, not being mixed with faith in them that heard it.","words":[["G2532","For",0,3],["G1063","For",0,3],["G2070","unto us was",4,15],["G2097","the gospel preached",16,35],["G2509","as well as",37,47],["G2548","unto them",48,57],["G0235","but",59,62],["G3056","the word",63,71],["G0189","preached",72,80],["G5623","did",81,84],["G3756","not",85,88],["G5623","profit",89,95],["G1565","them",96,100],["G3361","not",102,105],["G4786","being mixed",106,117],["G4102","with faith",118,128],["G0191","in them that heard",129,147]]},"4:3":{"text":"For we which have believed do enter into rest, as he said, As I have sworn in my wrath, if they shall enter into my rest: although the works were finished from the foundation of the world.","words":[["G1063","For",0,3],["G3588","we which",4,12],["G4100","have believed",13,26],["G1525","do enter",27,35],["G1519","into",36,40],["G2663","rest",41,45],["G2531","as",47,49],["G2046","he said",50,57],["G5613","As",59,61],["G3660","I have sworn",62,74],["G1722","in",75,77],["G3450","my",78,80],["G3709","wrath",81,86],["G1487","if",88,90],["G1525","they shall enter",91,107],["G1519","into",108,112],["G3450","my",113,115],["G2663","rest",116,120],["G2543","although",122,130],["G2041","the works",131,140],["G1096","were finished",141,154],["G0575","from",155,159],["G2602","the foundation",160,174],["G2889","of the world",175,187]]},"4:4":{"text":"For he spake in a certain place of the seventh day on this wise, And God did rest the seventh day from all his works.","words":[["G1063","For",0,3],["G2046","he spake",4,12],["G4225","in a certain place",13,31],["G4012","of",32,34],["G1442","the seventh",35,46],["G3779","day on this wise",47,63],["G2532","And",65,68],["G2316","God",69,72],["G2664","did rest",73,81],["G1722","the seventh",82,93],["G1442","the seventh",82,93],["G2250","day",94,97],["G0575","from",98,102],["G3956","all",103,106],["G0846","his",107,110],["G2041","works",111,116]]},"4:5":{"text":"And in this place again, If they shall enter into my rest.","words":[["G2532","And",0,3],["G1722","in",4,6],["G5129","this",7,11],["G3825","place again",12,23],["G1487","If",25,27],["G1525","they shall enter",28,44],["G1519","into",45,49],["G3450","my",50,52],["G2663","rest",53,57]]},"4:6":{"text":"Seeing therefore it remaineth that some must enter therein, and they to whom it was first preached entered not in because of unbelief:","words":[["G1893","Seeing",0,6],["G3767","therefore",7,16],["G0620","it remaineth",17,29],["G5100","that some",30,39],["G1525","must enter",40,50],["G1519","therein",51,58],["G0846","therein",51,58],["G2532","and",60,63],["G4386","they to whom it was first",64,89],["G2097","preached",90,98],["G1525","entered",99,106],["G3756","not",107,110],["G1525","in",111,113],["G1223","because",114,121],["G0543","of unbelief",122,133]]},"4:7":{"text":"Again, he limiteth a certain day, saying in David, To day, after so long a time; as it is said, To day if ye will hear his voice, harden not your hearts.","words":[["G3825","Again",0,5],["G3724","he limiteth",7,18],["G5100","a certain",19,28],["G2250","day",29,32],["G3004","saying",34,40],["G1722","in",41,43],["G1138","David",44,49],["G4594","To day",51,57],["G3326","after",59,64],["G5118","so long",65,72],["G5550","a time",73,79],["G2531","as",81,83],["G2046","it is said",84,94],["G4594","To day",96,102],["G1437","if",103,105],["G0191","ye will hear",106,118],["G0846","his",119,122],["G5456","voice",123,128],["G4645","harden",130,136],["G3361","not",137,140],["G5216","your",141,145],["G2588","hearts",146,152]]},"4:8":{"text":"For if Jesus had given them rest, then would he not afterward have spoken of another day.","words":[["G1063","For",0,3],["G1487","if",4,6],["G2424","Jesus",7,12],["G2664","had given",13,22],["G0846","them",23,27],["G2664","rest",28,32],["G0302","then would he",34,47],["G3756","not",48,51],["G3326","afterward",52,61],["G5023","afterward",52,61],["G2980","have spoken",62,73],["G4012","of",74,76],["G0243","another",77,84],["G2250","day",85,88]]},"4:9":{"text":"There remaineth therefore a rest to the people of God.","words":[["G0620","There remaineth",0,15],["G0686","therefore",16,25],["G4520","a rest",26,32],["G2992","to the people",33,46],["G2316","of God",47,53]]},"4:10":{"text":"For he that is entered into his rest, he also hath ceased from his own works, as God did from his.","words":[["G1063","For",0,3],["G1525","he that is entered",4,22],["G1519","into",23,27],["G0846","his",28,31],["G2663","rest",32,36],["G0846","he",38,40],["G2532","also",41,45],["G2664","hath ceased",46,57],["G0575","from",58,62],["G0846","his own",63,70],["G2041","works",71,76],["G5618","as",78,80],["G2316","God",81,84],["G0575","did from",85,93],["G2398","his",94,97]]},"4:11":{"text":"Let us labour therefore to enter into that rest, lest any man fall after the same example of unbelief.","words":[["G4704","Let us labour",0,13],["G3767","therefore",14,23],["G1525","to enter",24,32],["G1519","into",33,37],["G1565","that",38,42],["G2663","rest",43,47],["G3363","lest",49,53],["G5100","any man",54,61],["G4098","fall",62,66],["G1722","after",67,72],["G0846","the same",73,81],["G5262","example",82,89],["G0543","of unbelief",90,101]]},"4:12":{"text":"For the word of God is quick, and powerful, and sharper than any twoedged sword, piercing even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart.","words":[["G1063","For",0,3],["G3056","the word",4,12],["G2316","of God",13,19],["G2198","is quick",20,28],["G2532","and",30,33],["G1756","powerful",34,42],["G2532","and",44,47],["G5114","sharper",48,55],["G5228","than",56,60],["G3956","any",61,64],["G1366","twoedged",65,73],["G3162","sword",74,79],["G1338","piercing",81,89],["G0891","even to",90,97],["G3311","the dividing asunder",98,118],["G5590","of soul",119,126],["G5037","and",127,130],["G2532","and",127,130],["G4151","spirit",131,137],["G5037","and",139,142],["G2532","and",139,142],["G0719","of the joints",143,156],["G2532","and",157,160],["G3452","marrow",161,167],["G2532","and",169,172],["G2924","is a discerner",173,187],["G1761","of the thoughts",188,203],["G2532","and",204,207],["G1771","intents",208,215],["G2588","of the heart",216,228]]},"4:13":{"text":"Neither is there any creature that is not manifest in his sight: but all things are naked and opened unto the eyes of him with whom we have to do.","words":[["G2532","Neither",0,7],["G3756","Neither",0,7],["G2076","is there",8,16],["G2937","any creature",17,29],["G0852","that is not manifest",30,50],["G0846","in his",51,57],["G1799","sight",58,63],["G1161","but",65,68],["G3956","all things",69,79],["G1131","are naked",80,89],["G2532","and",90,93],["G5136","opened",94,100],["G3788","unto the eyes",101,114],["G0846","of him",115,121],["G4314","with",122,126],["G3739","whom",127,131],["G2254","we have",132,139],["G3056","to do",140,145]]},"4:14":{"text":"Seeing then that we have a great high priest, that is passed into the heavens, Jesus the Son of God, let us hold fast our profession.","words":[["G2192","Seeing",0,6],["G3767","then",7,11],["G2192","that we have",12,24],["G3173","a great",25,32],["G0749","high priest",33,44],["G1330","that is passed into",46,65],["G3772","the heavens",66,77],["G2424","Jesus",79,84],["G5207","the Son",85,92],["G2316","of God",93,99],["G2902","let us hold fast",101,117],["G3671","our profession",118,132]]},"4:15":{"text":"For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin.","words":[["G1063","For",0,3],["G2192","we have",4,11],["G3756","not",12,15],["G0749","an high priest",16,30],["G3361","which cannot",31,43],["G1410","which cannot",31,43],["G4834","be touched with the feeling",44,71],["G2257","of our",72,78],["G0769","infirmities",79,90],["G1161","but",92,95],["G3985","was",96,99],["G2596","in",100,102],["G3956","all points",103,113],["G3985","tempted",114,121],["G3987","tempted",114,121],["G2596","like",122,126],["G3665","as",127,129],["G5565","we are, yet without",130,149],["G0266","sin",150,153]]},"4:16":{"text":"Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need.","words":[["G4334","Let us",0,6],["G3767","therefore",7,16],["G4334","come",17,21],["G3326","boldly",22,28],["G3954","boldly",22,28],["G2362","unto the throne",29,44],["G5485","of grace",45,53],["G2443","that",55,59],["G2983","we may obtain",60,73],["G1656","mercy",74,79],["G2532","and",81,84],["G2147","find",85,89],["G5485","grace",90,95],["G0996","to help",96,103],["G1519","in",104,106],["G2121","time of need",107,119]]},"5:1":{"text":"For every high priest taken from among men is ordained for men in things pertaining to God, that he may offer both gifts and sacrifices for sins:","words":[["G1063","For",0,3],["G3956","every",4,9],["G0749","high priest",10,21],["G2983","taken",22,27],["G1537","from among",28,38],["G0444","men",39,42],["G2525","is ordained",43,54],["G5228","for",55,58],["G0444","men",59,62],["G4314","in things pertaining to",63,86],["G2316","God",87,90],["G2443","that",92,96],["G4374","he may offer",97,109],["G5037","both",110,114],["G1435","gifts",115,120],["G2532","and",121,124],["G2378","sacrifices",125,135],["G5228","for",136,139],["G0266","sins",140,144]]},"5:2":{"text":"Who can have compassion on the ignorant, and on them that are out of the way; for that he himself also is compassed with infirmity.","words":[["G1410","Who can",0,7],["G3356","have compassion",8,23],["G0050","on the ignorant",24,39],["G2532","and",41,44],["G4105","on them that are out of the way",45,76],["G1893","for",78,81],["G4029","that he",82,89],["G0846","himself",90,97],["G2532","also",98,102],["G4029","is compassed",103,115],["G0769","with infirmity",116,130]]},"5:3":{"text":"And by reason hereof he ought, as for the people, so also for himself, to offer for sins.","words":[["G2532","And",0,3],["G1223","by reason",4,13],["G5026","hereof",14,20],["G3784","he ought",21,29],["G2531","as",31,33],["G4012","for",34,37],["G2992","the people",38,48],["G3779","so",50,52],["G2532","also",53,57],["G4012","for",58,61],["G1438","himself",62,69],["G4374","to offer",71,79],["G5228","for",80,83],["G0266","sins",84,88]]},"5:4":{"text":"And no man taketh this honour unto himself, but he that is called of God, as was Aaron.","words":[["G2532","And",0,3],["G3756","no",4,6],["G5100","man",7,10],["G2983","taketh",11,17],["G5092","this honour",18,29],["G1438","unto himself",30,42],["G0235","but",44,47],["G2564","he that is called",48,65],["G5259","of",66,68],["G2316","God",69,72],["G2509","as",74,76],["G2532","as",74,76],["G0002","was Aaron",77,86]]},"5:5":{"text":"So also Christ glorified not himself to be made an high priest; but he that said unto him, Thou art my Son, to day have I begotten thee.","words":[["G3779","So",0,2],["G2532","also",3,7],["G5547","Christ",8,14],["G1392","glorified",15,24],["G3756","not",25,28],["G1438","himself",29,36],["G1096","to be made",37,47],["G0749","an high priest",48,62],["G0235","but",64,67],["G2980","he that said",68,80],["G4314","unto",81,85],["G0846","him",86,89],["G4771","Thou",91,95],["G1488","art",96,99],["G3450","my",100,102],["G5207","Son",103,106],["G4594","to day",108,114],["G1080","have",115,119],["G1473","I",120,121],["G1080","begotten",122,130],["G4571","thee",131,135]]},"5:6":{"text":"As he saith also in another place, Thou art a priest for ever after the order of Melchisedec.","words":[["G2531","As",0,2],["G3004","he saith",3,11],["G2532","also",12,16],["G1722","in",17,19],["G2087","another",20,27],["G4771","place, Thou",28,39],["G2409","art a priest",40,52],["G1519","for",53,56],["G0165","ever",57,61],["G2596","after",62,67],["G5010","the order",68,77],["G3198","of Melchisedec",78,92]]},"5:7":{"text":"Who in the days of his flesh, when he had offered up prayers and supplications with strong crying and tears unto him that was able to save him from death, and was heard in that he feared;","words":[["G3739","Who",0,3],["G1722","in",4,6],["G2250","the days",7,15],["G0846","of his",16,22],["G4561","flesh",23,28],["G4374","when he had offered up",30,52],["G1162","prayers",53,60],["G5037","and",61,64],["G2532","and",61,64],["G2428","supplications",65,78],["G3326","with",79,83],["G2478","strong",84,90],["G2906","crying",91,97],["G2532","and",98,101],["G1144","tears",102,107],["G4314","unto",108,112],["G1410","him that was able",113,130],["G4982","to save",131,138],["G0846","him",139,142],["G1537","from",143,147],["G2288","death",148,153],["G2532","and",155,158],["G1522","was heard",159,168],["G0575","in that",169,176],["G2124","he feared",177,186]]},"5:8":{"text":"Though he were a Son, yet learned he obedience by the things which he suffered;","words":[["G2539","Though",0,6],["G5607","he were",7,14],["G5207","a Son",15,20],["G3129","yet learned he",22,36],["G5218","obedience",37,46],["G0575","by",47,49],["G3739","the things which",50,66],["G3958","he suffered",67,78]]},"5:9":{"text":"And being made perfect, he became the author of eternal salvation unto all them that obey him;","words":[["G2532","And",0,3],["G5048","being made perfect",4,22],["G1096","he became",24,33],["G0159","the author",34,44],["G0166","of eternal",45,55],["G4991","salvation",56,65],["G3956","unto all",66,74],["G5219","them that obey",75,89],["G0846","him",90,93]]},"5:10":{"text":"Called of God an high priest after the order of Melchisedec.","words":[["G4316","Called",0,6],["G5259","of",7,9],["G2316","God",10,13],["G0749","an high priest",14,28],["G2596","after",29,34],["G5010","the order",35,44],["G3198","of Melchisedec",45,59]]},"5:11":{"text":"Of whom we have many things to say, and hard to be uttered, seeing ye are dull of hearing.","words":[["G4012","Of",0,2],["G3739","whom",3,7],["G2254","we",8,10],["G3056","have",11,15],["G4183","many things",16,27],["G3056","to say",28,34],["G2532","and",36,39],["G1421","hard",40,44],["G3004","to be uttered",45,58],["G1893","seeing",60,66],["G1096","ye are",67,73],["G3576","dull",74,78],["G0189","of hearing",79,89]]},"5:12":{"text":"For when for the time ye ought to be teachers, ye have need that one teach you again which be the first principles of the oracles of God; and are become such as have need of milk, and not of strong meat.","words":[["G2532","For",0,3],["G1063","For",0,3],["G1223","when for",4,12],["G5550","the time",13,21],["G3784","ye ought",22,30],["G1511","to be",31,36],["G1320","teachers",37,45],["G2192","ye have",47,54],["G5532","need",55,59],["G1321","that one teach",60,74],["G5209","you",75,78],["G3825","again",79,84],["G5101","which",85,90],["G0746","be the first",91,103],["G4747","principles",104,114],["G3051","of the oracles",115,129],["G2316","of God",130,136],["G2532","and",138,141],["G1096","are become such as",142,160],["G2192","have",161,165],["G5532","need",166,170],["G1051","of milk",171,178],["G2532","and",180,183],["G3756","not",184,187],["G4731","of strong",188,197],["G5160","meat",198,202]]},"5:13":{"text":"For every one that useth milk is unskilful in the word of righteousness: for he is a babe.","words":[["G1063","For",0,3],["G3956","every one",4,13],["G3348","that useth",14,24],["G1051","milk",25,29],["G0552","is unskilful",30,42],["G3056","in the word",43,54],["G1343","of righteousness",55,71],["G1063","for",73,76],["G2076","he is",77,82],["G3516","a babe",83,89]]},"5:14":{"text":"But strong meat belongeth to them that are of full age, even those who by reason of use have their senses exercised to discern both good and evil.","words":[["G1161","But",0,3],["G4731","strong",4,10],["G5160","meat",11,15],["G2076","belongeth to them that are",16,42],["G5046","of full age",43,54],["G1223","even those who by reason",56,80],["G1838","of use",81,87],["G2192","have",88,92],["G0145","their senses",93,105],["G1128","exercised",106,115],["G4314","to",116,118],["G1253","discern",119,126],["G5037","both",127,131],["G2570","good",132,136],["G2532","and",137,140],["G2556","evil",141,145]]},"6:1":{"text":"Therefore leaving the principles of the doctrine of Christ, let us go on unto perfection; not laying again the foundation of repentance from dead works, and of faith toward God,","words":[["G1352","Therefore",0,9],["G0863","leaving",10,17],["G0746","the principles",18,32],["G3056","of the doctrine",33,48],["G5547","of Christ",49,58],["G5342","let us go on",60,72],["G1909","unto",73,77],["G5047","perfection",78,88],["G3361","not",90,93],["G2598","laying",94,100],["G3825","again",101,106],["G2310","the foundation",107,121],["G3341","of repentance",122,135],["G0575","from",136,140],["G3498","dead",141,145],["G2041","works",146,151],["G2532","and",153,156],["G4102","of faith",157,165],["G1909","toward",166,172],["G2316","God",173,176]]},"6:2":{"text":"Of the doctrine of baptisms, and of laying on of hands, and of resurrection of the dead, and of eternal judgment.","words":[["G1322","Of the doctrine",0,15],["G0909","of baptisms",16,27],["G5037","and",29,32],["G1936","of laying on",33,45],["G5495","of hands",46,54],["G5037","and",56,59],["G0386","of resurrection",60,75],["G3498","of the dead",76,87],["G2532","and",89,92],["G0166","of eternal",93,103],["G2917","judgment",104,112]]},"6:3":{"text":"And this will we do, if God permit.","words":[["G2532","And",0,3],["G5124","this",4,8],["G4160","will we do",9,19],["G1437","if",21,23],["G4007","if",21,23],["G2316","God",24,27],["G2010","permit",28,34]]},"6:4":{"text":"For it is impossible for those who were once enlightened, and have tasted of the heavenly gift, and were made partakers of the Holy Ghost,","words":[["G1063","For",0,3],["G0102","it is impossible",4,20],["G0530","for those who were once",21,44],["G5461","enlightened",45,56],["G5037","and",58,61],["G1089","have tasted",62,73],["G2032","of the heavenly",74,89],["G1431","gift",90,94],["G2532","and",96,99],["G1096","were made",100,109],["G3353","partakers",110,119],["G0040","of the Holy",120,131],["G4151","Ghost",132,137]]},"6:5":{"text":"And have tasted the good word of God, and the powers of the world to come,","words":[["G2532","And",0,3],["G1089","have tasted",4,15],["G2570","the good",16,24],["G4487","word",25,29],["G2316","of God",30,36],["G5037","and",38,41],["G1411","the powers",42,52],["G0165","of the world",53,65],["G3195","to come",66,73]]},"6:6":{"text":"If they shall fall away, to renew them again unto repentance; seeing they crucify to themselves the Son of God afresh, and put him to an open shame.","words":[["G2532","If",0,2],["G3895","they shall fall away",3,23],["G0340","to renew them",25,38],["G3825","again",39,44],["G1519","unto",45,49],["G3341","repentance",50,60],["G0388","seeing they crucify",62,81],["G1438","to themselves",82,95],["G5207","the Son",96,103],["G2316","of God",104,110],["G0388","afresh",111,117],["G2532","and",119,122],["G3856","put him to an open shame",123,147]]},"6:7":{"text":"For the earth which drinketh in the rain that cometh oft upon it, and bringeth forth herbs meet for them by whom it is dressed, receiveth blessing from God:","words":[["G1063","For",0,3],["G1093","the earth",4,13],["G3588","which",14,19],["G4095","drinketh in",20,31],["G5205","the rain",32,40],["G2064","that cometh",41,52],["G4178","oft",53,56],["G1909","upon",57,61],["G0846","it",62,64],["G2532","and",66,69],["G5088","bringeth forth",70,84],["G1008","herbs",85,90],["G2111","meet",91,95],["G1565","for them",96,104],["G2532","for them",96,104],["G1223","by",105,107],["G3739","whom",108,112],["G1090","it is dressed",113,126],["G3335","receiveth",128,137],["G2129","blessing",138,146],["G0575","from",147,151],["G2316","God",152,155]]},"6:8":{"text":"But that which beareth thorns and briers is rejected, and is nigh unto cursing; whose end is to be burned.","words":[["G1161","But",0,3],["G1627","that which beareth",4,22],["G0173","thorns",23,29],["G2532","and",30,33],["G5146","briers",34,40],["G0096","is rejected",41,52],["G2532","and",54,57],["G1451","is nigh",58,65],["G2671","unto cursing",66,78],["G3739","whose",80,85],["G5056","end",86,89],["G1519","is to",90,95],["G2740","be burned",96,105]]},"6:9":{"text":"But, beloved, we are persuaded better things of you, and things that accompany salvation, though we thus speak.","words":[["G1161","But",0,3],["G0027","beloved",5,12],["G3982","we are persuaded",14,30],["G2909","better things",31,44],["G4012","of",45,47],["G5216","you",48,51],["G2532","and",53,56],["G2192","things that accompany",57,78],["G4991","salvation",79,88],["G1499","though",90,96],["G2980","we",97,99],["G3779","thus",100,104],["G2980","speak",105,110]]},"6:10":{"text":"For God is not unrighteous to forget your work and labour of love, which ye have shewed toward his name, in that ye have ministered to the saints, and do minister.","words":[["G1063","For",0,3],["G2316","God",4,7],["G3756","is not",8,14],["G0094","unrighteous",15,26],["G1950","to forget",27,36],["G5216","your",37,41],["G2041","work",42,46],["G2532","and",47,50],["G2873","labour",51,57],["G0026","of love",58,65],["G3739","which",67,72],["G1731","ye have shewed",73,87],["G1731","ye have shewed",73,87],["G1519","toward",88,94],["G0846","his",95,98],["G3686","name",99,103],["G1247","in that ye have ministered",105,131],["G0040","to the saints",132,145],["G2532","and",147,150],["G1247","do minister",151,162]]},"6:11":{"text":"And we desire that every one of you do shew the same diligence to the full assurance of hope unto the end:","words":[["G1161","And",0,3],["G1937","we desire",4,13],["G1538","that every one",14,28],["G5216","of you",29,35],["G1731","do shew",36,43],["G0846","the same",44,52],["G4710","diligence",53,62],["G4314","to",63,65],["G4136","the full assurance",66,84],["G1680","of hope",85,92],["G0891","unto",93,97],["G5056","the end",98,105]]},"6:12":{"text":"That ye be not slothful, but followers of them who through faith and patience inherit the promises.","words":[["G3363","That",0,4],["G1096","ye be",5,10],["G3363","not",11,14],["G3576","slothful",15,23],["G1161","but",25,28],["G3402","followers",29,38],["G1223","of them who through",39,58],["G4102","faith",59,64],["G2532","and",65,68],["G3115","patience",69,77],["G2816","inherit",78,85],["G1860","the promises",86,98]]},"6:13":{"text":"For when God made promise to Abraham, because he could swear by no greater, he sware by himself,","words":[["G1063","For",0,3],["G2316","when God",4,12],["G1861","made promise",13,25],["G0011","to Abraham",26,36],["G1893","because",38,45],["G2192","he could",46,54],["G3660","swear",55,60],["G2596","by",61,63],["G3762","no",64,66],["G3187","greater",67,74],["G3660","he sware",76,84],["G2596","by",85,87],["G1438","himself",88,95]]},"6:14":{"text":"Saying, Surely blessing I will bless thee, and multiplying I will multiply thee.","words":[["G3004","Saying",0,6],["G2229","Surely",8,14],["G3375","Surely",8,14],["G2127","blessing",15,23],["G2127","I will bless",24,36],["G4571","thee",37,41],["G2532","and",43,46],["G4129","multiplying",47,58],["G4129","I will multiply",59,74],["G4571","thee",75,79]]},"6:15":{"text":"And so, after he had patiently endured, he obtained the promise.","words":[["G2532","And",0,3],["G3779","so",4,6],["G3114","after he had patiently endured",8,38],["G2013","he obtained",40,51],["G1860","the promise",52,63]]},"6:16":{"text":"For men verily swear by the greater: and an oath for confirmation is to them an end of all strife.","words":[["G1063","For",0,3],["G0444","men",4,7],["G3303","verily",8,14],["G3660","swear",15,20],["G2596","by",21,23],["G3187","the greater",24,35],["G2532","and",37,40],["G3727","an oath",41,48],["G1519","for",49,52],["G0951","confirmation",53,65],["G0846","is to them",66,76],["G4009","an end",77,83],["G3956","of all",84,90],["G0485","strife",91,97]]},"6:17":{"text":"Wherein God, willing more abundantly to shew unto the heirs of promise the immutability of his counsel, confirmed it by an oath:","words":[["G1722","Wherein",0,7],["G3739","Wherein",0,7],["G2316","God",8,11],["G1014","willing",13,20],["G4054","more abundantly",21,36],["G1925","to shew",37,44],["G2818","unto the heirs",45,59],["G1860","of promise",60,70],["G0276","the immutability",71,87],["G0846","of his",88,94],["G1012","counsel",95,102],["G3315","confirmed",104,113],["G3727","it by an oath",114,127]]},"6:18":{"text":"That by two immutable things, in which it was impossible for God to lie, we might have a strong consolation, who have fled for refuge to lay hold upon the hope set before us:","words":[["G2443","That",0,4],["G1223","by",5,7],["G1417","two",8,11],["G0276","immutable",12,21],["G4229","things",22,28],["G1722","in",30,32],["G3739","which",33,38],["G0102","it was impossible",39,56],["G2316","for God",57,64],["G5574","to lie",65,71],["G2192","we might have",73,86],["G2478","a strong",87,95],["G3874","consolation",96,107],["G3588","who",109,112],["G2703","have fled for refuge",113,133],["G2902","to lay hold",134,145],["G1680","upon the hope",146,159],["G4295","set before us",160,173]]},"6:19":{"text":"Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil;","words":[["G3739","Which",0,5],["G2192","hope we have",6,18],["G5613","as",19,21],["G0045","an anchor",22,31],["G5590","of the soul",32,43],["G5037","both",45,49],["G0804","sure",50,54],["G2532","and",55,58],["G0949","stedfast",59,67],["G2532","and",69,72],["G1525","which entereth",73,87],["G1519","into",88,92],["G2082","that within",93,104],["G2665","the veil",105,113]]},"6:20":{"text":"Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec.","words":[["G3699","Whither",0,7],["G4274","the forerunner",8,22],["G1525","is",23,25],["G5228","for",26,29],["G2257","us",30,32],["G1525","entered",33,40],["G2424","even Jesus",42,52],["G1096","made",54,58],["G0749","an high priest",59,73],["G1519","for",74,77],["G0165","ever",78,82],["G2596","after",83,88],["G5010","the order",89,98],["G3198","of Melchisedec",99,113]]},"7:1":{"text":"For this Melchisedec, king of Salem, priest of the most high God, who met Abraham returning from the slaughter of the kings, and blessed him;","words":[["G1063","For",0,3],["G3778","this",4,8],["G3198","Melchisedec",9,20],["G0935","king",22,26],["G4532","of Salem",27,35],["G2409","priest",37,43],["G5310","of the most high",44,60],["G2316","God",61,64],["G3588","who",66,69],["G4876","met",70,73],["G0011","Abraham",74,81],["G5290","returning",82,91],["G0575","from",92,96],["G2871","the slaughter",97,110],["G0935","of the kings",111,123],["G2532","and",125,128],["G2127","blessed",129,136],["G0846","him",137,140]]},"7:2":{"text":"To whom also Abraham gave a tenth part of all; first being by interpretation King of righteousness, and after that also King of Salem, which is, King of peace;","words":[["G3739","To whom",0,7],["G2532","also",8,12],["G0011","Abraham",13,20],["G3307","gave",21,25],["G1181","a tenth part",26,38],["G0575","of",39,41],["G3956","all",42,45],["G4412","first",47,52],["G3303","first",47,52],["G2059","being by interpretation",53,76],["G0935","King",77,81],["G1343","of righteousness",82,98],["G1161","and",100,103],["G1899","after that",104,114],["G2532","also",115,119],["G0935","King",120,124],["G4532","of Salem",125,133],["G3603","which is",135,143],["G0935","King",145,149],["G1515","of peace",150,158]]},"7:3":{"text":"Without father, without mother, without descent, having neither beginning of days, nor end of life; but made like unto the Son of God; abideth a priest continually.","words":[["G0540","Without father",0,14],["G0282","without mother",16,30],["G0035","without descent",32,47],["G2192","having",49,55],["G3383","neither",56,63],["G0746","beginning",64,73],["G2250","of days",74,81],["G3383","nor",83,86],["G5056","end",87,90],["G2222","of life",91,98],["G1161","but",100,103],["G0871","made like",104,113],["G5207","unto the Son",114,126],["G2316","of God",127,133],["G3306","abideth",135,142],["G2409","a priest",143,151],["G1519","continually",152,163],["G1336","continually",152,163]]},"7:4":{"text":"Now consider how great this man was, unto whom even the patriarch Abraham gave the tenth of the spoils.","words":[["G1161","Now",0,3],["G2334","consider",4,12],["G4080","how great",13,22],["G3778","this man",23,31],["G3739","was, unto whom",32,46],["G2532","even",47,51],["G3966","the patriarch",52,65],["G0011","Abraham",66,73],["G1325","gave",74,78],["G1181","the tenth",79,88],["G1537","of",89,91],["G0205","the spoils",92,102]]},"7:5":{"text":"And verily they that are of the sons of Levi, who receive the office of the priesthood, have a commandment to take tithes of the people according to the law, that is, of their brethren, though they come out of the loins of Abraham:","words":[["G2532","And",0,3],["G3303","verily",4,10],["G1537","they that are of",11,27],["G5207","the sons",28,36],["G3017","of Levi",37,44],["G3588","who",46,49],["G2983","receive",50,57],["G2405","the office of the priesthood",58,86],["G2192","have",88,92],["G1785","a commandment",93,106],["G0586","to take tithes",107,121],["G2992","of the people",122,135],["G2596","according to",136,148],["G3551","the law",149,156],["G5123","that is",158,165],["G0846","of their",167,175],["G0080","brethren",176,184],["G2539","though",186,192],["G1831","they come",193,202],["G1537","out of",203,209],["G3751","the loins",210,219],["G0011","of Abraham",220,230]]},"7:6":{"text":"But he whose descent is not counted from them received tithes of Abraham, and blessed him that had the promises.","words":[["G1161","But",0,3],["G1075","he whose descent is",4,23],["G3361","not",24,27],["G1075","counted",28,35],["G1537","from",36,40],["G0846","them",41,45],["G1183","received tithes",46,61],["G0011","of Abraham",62,72],["G2532","and",74,77],["G2127","blessed",78,85],["G2192","him that had",86,98],["G1860","the promises",99,111]]},"7:7":{"text":"And without all contradiction the less is blessed of the better.","words":[["G1161","And",0,3],["G5565","without",4,11],["G3956","all",12,15],["G0485","contradiction",16,29],["G1640","the less",30,38],["G2127","is blessed",39,49],["G5259","of",50,52],["G2909","the better",53,63]]},"7:8":{"text":"And here men that die receive tithes; but there he receiveth them, of whom it is witnessed that he liveth.","words":[["G2532","And",0,3],["G5602","here",4,8],["G3303","here",4,8],["G0444","men",9,12],["G0599","that die",13,21],["G2983","receive",22,29],["G1181","tithes",30,36],["G1161","but",38,41],["G1563","there",42,47],["G3140","he receiveth them, of whom it is witnessed",48,90],["G3754","that",91,95],["G2198","he liveth",96,105]]},"7:9":{"text":"And as I may so say, Levi also, who receiveth tithes, payed tithes in Abraham.","words":[["G2532","And",0,3],["G5613","as",4,6],["G2031","I may so say",7,19],["G2036","I may so say",7,19],["G3017","Levi",21,25],["G2532","also",26,30],["G3588","who",32,35],["G2983","receiveth",36,45],["G1181","tithes",46,52],["G1183","payed tithes",54,66],["G1223","in",67,69],["G0011","Abraham",70,77]]},"7:10":{"text":"For he was yet in the loins of his father, when Melchisedec met him.","words":[["G1063","For",0,3],["G2258","he was",4,10],["G2089","yet",11,14],["G1722","in",15,17],["G3751","the loins",18,27],["G3962","of his father",28,41],["G3753","when",43,47],["G3198","Melchisedec",48,59],["G4876","met",60,63],["G0846","him",64,67]]},"7:11":{"text":"If therefore perfection were by the Levitical priesthood, (for under it the people received the law,) what further need was there that another priest should rise after the order of Melchisedec, and not be called after the order of Aaron?","words":[["G1487","If",0,2],["G3303","If",0,2],["G3767","therefore",3,12],["G5050","perfection",13,23],["G2258","were",24,28],["G1223","by",29,31],["G3020","the Levitical",32,45],["G2420","priesthood",46,56],["G1063","(for",58,62],["G1909","under",63,68],["G0846","it",69,71],["G2992","the people",72,82],["G3549","received the law",83,99],["G5101",") what",100,106],["G2089","further",107,114],["G5532","need",115,119],["G2087","was there that another",120,142],["G2409","priest",143,149],["G0450","should rise",150,161],["G2596","after",162,167],["G5010","the order",168,177],["G3198","of Melchisedec",178,192],["G2532","and",194,197],["G3756","not",198,201],["G3004","be called",202,211],["G2596","after",212,217],["G5010","the order",218,227],["G0002","of Aaron",228,236]]},"7:12":{"text":"For the priesthood being changed, there is made of necessity a change also of the law.","words":[["G1063","For",0,3],["G2420","the priesthood",4,18],["G3346","being changed",19,32],["G1096","there is made",34,47],["G1537","of",48,50],["G0318","necessity",51,60],["G3331","a change",61,69],["G2532","also",70,74],["G3551","of the law",75,85]]},"7:13":{"text":"For he of whom these things are spoken pertaineth to another tribe, of which no man gave attendance at the altar.","words":[["G1063","For",0,3],["G1909","he of",4,9],["G3739","whom",10,14],["G5023","these things",15,27],["G3004","are spoken",28,38],["G3348","pertaineth",39,49],["G2087","to another",50,60],["G5443","tribe",61,66],["G0575","of",68,70],["G3739","which",71,76],["G3762","no man",77,83],["G4337","gave attendance",84,99],["G2379","at the altar",100,112]]},"7:14":{"text":"For it is evident that our Lord sprang out of Juda; of which tribe Moses spake nothing concerning priesthood.","words":[["G1063","For",0,3],["G4271","it is evident",4,17],["G3754","that",18,22],["G2257","our",23,26],["G2962","Lord",27,31],["G0393","sprang",32,38],["G1537","out of",39,45],["G2455","Juda",46,50],["G1519","of",52,54],["G3739","which",55,60],["G5443","tribe",61,66],["G3475","Moses",67,72],["G2980","spake",73,78],["G3762","nothing",79,86],["G4012","concerning",87,97],["G2420","priesthood",98,108]]},"7:15":{"text":"And it is yet far more evident: for that after the similitude of Melchisedec there ariseth another priest,","words":[["G2532","And",0,3],["G2076","it is",4,9],["G2089","yet",10,13],["G4054","far more",14,22],["G2612","evident",23,30],["G1487","for",32,35],["G2596","that after",36,46],["G3665","the similitude",47,61],["G3198","of Melchisedec",62,76],["G0450","there ariseth",77,90],["G2087","another",91,98],["G2409","priest",99,105]]},"7:16":{"text":"Who is made, not after the law of a carnal commandment, but after the power of an endless life.","words":[["G3739","Who",0,3],["G1096","is made",4,11],["G3756","not",13,16],["G2596","after",17,22],["G3551","the law",23,30],["G4559","of a carnal",31,42],["G1785","commandment",43,54],["G0235","but",56,59],["G2596","after",60,65],["G1411","the power",66,75],["G0179","of an endless",76,89],["G2222","life",90,94]]},"7:17":{"text":"For he testifieth, Thou art a priest for ever after the order of Melchisedec.","words":[["G1063","For",0,3],["G3140","he testifieth",4,17],["G3754","",-1,-1],["G4771","Thou",19,23],["G2409","art a priest",24,36],["G1519","for",37,40],["G0165","ever",41,45],["G2596","after",46,51],["G5010","the order",52,61],["G3198","of Melchisedec",62,76]]},"7:18":{"text":"For there is verily a disannulling of the commandment going before for the weakness and unprofitableness thereof.","words":[["G1063","For",0,3],["G1096","there is",4,12],["G3303","verily",13,19],["G0115","a disannulling",20,34],["G1785","of the commandment",35,53],["G4254","going before",54,66],["G1223","for",67,70],["G0772","the weakness",71,83],["G2532","and",84,87],["G0512","unprofitableness",88,104],["G0846","thereof",105,112]]},"7:19":{"text":"For the law made nothing perfect, but the bringing in of a better hope did; by the which we draw nigh unto God.","words":[["G1063","For",0,3],["G3551","the law",4,11],["G5048","made",12,16],["G3762","nothing",17,24],["G5048","perfect",25,32],["G1161","but",34,37],["G1898","the bringing in",38,53],["G2909","of a better",54,65],["G1680","hope",66,70],["G1223","did; by",71,78],["G3739","the which",79,88],["G1448","we draw nigh",89,101],["G2316","unto God",102,110]]},"7:20":{"text":"And inasmuch as not without an oath he was made priest:","words":[["G2532","And",0,3],["G2596","inasmuch as",4,15],["G3745","inasmuch as",4,15],["G3756","not",16,19],["G5565","without",20,27],["G3728","an oath",28,35]]},"7:21":{"text":"(For those priests were made without an oath; but this with an oath by him that said unto him, The Lord sware and will not repent, Thou art a priest for ever after the order of Melchisedec:)","words":[["G1063","(For",0,4],["G2409","those priests",5,18],["G3303","were",19,23],["G1526","were",19,23],["G1096","made",24,28],["G5565","without",29,36],["G3728","an oath",37,44],["G1161","but",46,49],["G3326","this with",50,59],["G3728","an oath",60,67],["G1223","by",68,70],["G3004","him that said",71,84],["G4314","unto",85,89],["G0846","him",90,93],["G2962","The Lord",95,103],["G3660","sware",104,109],["G2532","and",110,113],["G3338","will",114,118],["G3756","not",119,122],["G3338","repent",123,129],["G4771","Thou",131,135],["G2409","art a priest",136,148],["G1519","for",149,152],["G0165","ever",153,157],["G2596","after",158,163],["G5010","the order",164,173],["G3198","of Melchisedec",174,188]]},"7:22":{"text":"By so much was Jesus made a surety of a better testament.","words":[["G2596","By",0,2],["G5118","so much",3,10],["G1096","was",11,14],["G2424","Jesus",15,20],["G1096","made",21,25],["G1450","a surety",26,34],["G2909","of a better",35,46],["G1242","testament",47,56]]},"7:23":{"text":"And they truly were many priests, because they were not suffered to continue by reason of death:","words":[["G2532","And",0,3],["G1526","they",4,8],["G3303","truly",9,14],["G1526","were",15,19],["G1096","were",15,19],["G4119","many",20,24],["G2409","priests",25,32],["G2967","because they were not suffered",34,64],["G3887","to continue",65,76],["G1223","by reason of",77,89],["G2288","death",90,95]]},"7:24":{"text":"But this man, because he continueth ever, hath an unchangeable priesthood.","words":[["G1161","But",0,3],["G1223","this man, because",4,21],["G0846","he",22,24],["G3306","continueth",25,35],["G1519","ever",36,40],["G0165","ever",36,40],["G2192","hath",42,46],["G0531","an unchangeable",47,62],["G2420","priesthood",63,73]]},"7:25":{"text":"Wherefore he is able also to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them.","words":[["G3606","Wherefore",0,9],["G1410","he is able",10,20],["G2532","also",21,25],["G4982","to save them",26,38],["G1519","to",39,41],["G3838","the uttermost",42,55],["G4334","that come",56,65],["G2316","unto God",66,74],["G1223","by",75,77],["G0846","him",78,81],["G3842","seeing he ever",83,97],["G2198","liveth",98,104],["G1519","to",105,107],["G1793","make intercession",108,125],["G5228","for",126,129],["G0846","them",130,134]]},"7:26":{"text":"For such an high priest became us, who is holy, harmless, undefiled, separate from sinners, and made higher than the heavens;","words":[["G1063","For",0,3],["G5108","such",4,8],["G0749","an high priest",9,23],["G4241","became",24,30],["G2254","us",31,33],["G3741","who is holy",35,46],["G0172","harmless",48,56],["G0283","undefiled",58,67],["G5563","separate",69,77],["G0575","from",78,82],["G0268","sinners",83,90],["G2532","and",92,95],["G1096","made",96,100],["G5308","higher than",101,112],["G3772","the heavens",113,124]]},"7:27":{"text":"Who needeth not daily, as those high priests, to offer up sacrifice, first for his own sins, and then for the people's: for this he did once, when he offered up himself.","words":[["G3739","Who",0,3],["G2192","needeth",4,11],["G0318","needeth",4,11],["G3756","not",12,15],["G2596","daily",16,21],["G2250","daily",16,21],["G5618","as",23,25],["G0749","those high priests",26,44],["G0399","to offer up",46,57],["G2378","sacrifice",58,67],["G4386","first",69,74],["G5228","for",75,78],["G2398","his own",79,86],["G0266","sins",87,91],["G1899","and then",93,101],["G2992","for the people's",102,118],["G1063","for",120,123],["G5124","this",124,128],["G4160","he did",129,135],["G2178","once",136,140],["G0399","when he offered up",142,160],["G1438","himself",161,168]]},"7:28":{"text":"For the law maketh men high priests which have infirmity; but the word of the oath, which was since the law, maketh the Son, who is consecrated for evermore.","words":[["G1063","For",0,3],["G3551","the law",4,11],["G2525","maketh",12,18],["G0444","men",19,22],["G0749","high priests",23,35],["G2192","which have",36,46],["G0769","infirmity",47,56],["G1161","but",58,61],["G3056","the word",62,70],["G3728","of the oath",71,82],["G3588","which",84,89],["G3326","was since",90,99],["G3551","the law",100,107],["G5207","maketh the Son",109,123],["G5048","who is consecrated",125,143],["G1519","for",144,147],["G0165","evermore",148,156]]},"8:1":{"text":"Now of the things which we have spoken this is the sum: We have such an high priest, who is set on the right hand of the throne of the Majesty in the heavens;","words":[["G1161","Now",0,3],["G1909","of",4,6],["G3004","the things which we have spoken",7,38],["G2774","this is the sum",39,54],["G2192","We have",56,63],["G5108","such",64,68],["G0749","an high priest",69,83],["G3739","who",85,88],["G2523","is set",89,95],["G1722","on",96,98],["G1188","the right hand",99,113],["G2362","of the throne",114,127],["G3172","of the Majesty",128,142],["G1722","in",143,145],["G3772","the heavens",146,157]]},"8:2":{"text":"A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man.","words":[["G3011","A minister",0,10],["G0039","of the sanctuary",11,27],["G2532","and",29,32],["G0228","of the true",33,44],["G4633","tabernacle",45,55],["G3739","which",57,62],["G2962","the Lord",63,71],["G4078","pitched",72,79],["G2532","and",81,84],["G3756","not",85,88],["G0444","man",89,92]]},"8:3":{"text":"For every high priest is ordained to offer gifts and sacrifices: wherefore it is of necessity that this man have somewhat also to offer.","words":[["G1063","For",0,3],["G3956","every",4,9],["G0749","high priest",10,21],["G2525","is ordained",22,33],["G1519","to",34,36],["G4374","offer",37,42],["G1435","gifts",43,48],["G5037","and",49,52],["G2532","and",49,52],["G2378","sacrifices",53,63],["G3606","wherefore",65,74],["G0316","it is of necessity",75,93],["G5126","that this man",94,107],["G2192","have",108,112],["G5100","somewhat",113,121],["G2532","also",122,126],["G3739","to",127,129],["G4374","offer",130,135]]},"8:4":{"text":"For if he were on earth, he should not be a priest, seeing that there are priests that offer gifts according to the law:","words":[["G1063","For",0,3],["G1487","if",4,6],["G3303","if",4,6],["G2258","he were",7,14],["G1909","on",15,17],["G1093","earth",18,23],["G0302","he should",25,34],["G3761","not",35,38],["G2258","be",39,41],["G2409","a priest",42,50],["G5607","seeing that there are",52,73],["G2409","priests",74,81],["G4374","that offer",82,92],["G1435","gifts",93,98],["G2596","according",99,108],["G3551","to the law",109,119]]},"8:5":{"text":"Who serve unto the example and shadow of heavenly things, as Moses was admonished of God when he was about to make the tabernacle: for, See, saith he, that thou make all things according to the pattern shewed to thee in the mount.","words":[["G3748","Who",0,3],["G3000","serve",4,9],["G5262","unto the example",10,26],["G2532","and",27,30],["G4639","shadow",31,37],["G2032","of heavenly things",38,56],["G2531","as",58,60],["G3475","Moses",61,66],["G5537","was admonished of God",67,88],["G3195","when he was about",89,106],["G2005","to make",107,114],["G4633","the tabernacle",115,129],["G1063","for",131,134],["G3708","See",136,139],["G5346","saith he",141,149],["G4160","that thou make",151,165],["G3956","all things",166,176],["G2596","according to",177,189],["G5179","the pattern",190,201],["G1166","shewed",202,208],["G4671","to thee",209,216],["G1722","in",217,219],["G3735","the mount",220,229]]},"8:6":{"text":"But now hath he obtained a more excellent ministry, by how much also he is the mediator of a better covenant, which was established upon better promises.","words":[["G1161","But",0,3],["G3570","now",4,7],["G5177","hath he obtained",8,24],["G1313","a more excellent",25,41],["G3009","ministry",42,50],["G3745","by how much",52,63],["G2532","also",64,68],["G2076","he is",69,74],["G3316","the mediator",75,87],["G2909","of a better",88,99],["G1242","covenant",100,108],["G3748","which",110,115],["G3549","was established",116,131],["G1909","upon",132,136],["G2909","better",137,143],["G1860","promises",144,152]]},"8:7":{"text":"For if that first covenant had been faultless, then should no place have been sought for the second.","words":[["G1063","For",0,3],["G1487","if",4,6],["G1565","that",7,11],["G4413","first",12,17],["G2258","covenant had been",18,35],["G0273","faultless",36,45],["G0302","then should",47,58],["G3756","no",59,61],["G5117","place",62,67],["G2212","have been sought",68,84],["G1208","for the second",85,99]]},"8:8":{"text":"For finding fault with them, he saith, Behold, the days come, saith the Lord, when I will make a new covenant with the house of Israel and with the house of Judah:","words":[["G1063","For",0,3],["G3201","finding fault",4,17],["G0846","with them",18,27],["G3004","he saith",29,37],["G2400","Behold",39,45],["G2250","the days",47,55],["G2064","come",56,60],["G3004","saith",62,67],["G2962","the Lord",68,76],["G2532","when",78,82],["G4931","I will make",83,94],["G2537","a new",95,100],["G1242","covenant",101,109],["G1909","with",110,114],["G3624","the house",115,124],["G2474","of Israel",125,134],["G2532","and",135,138],["G1909","with",139,143],["G3624","the house",144,153],["G2455","of Judah",154,162]]},"8:9":{"text":"Not according to the covenant that I made with their fathers in the day when I took them by the hand to lead them out of the land of Egypt; because they continued not in my covenant, and I regarded them not, saith the Lord.","words":[["G3756","Not",0,3],["G2596","according to",4,16],["G1242","the covenant",17,29],["G3739","that",30,34],["G4160","I made with",35,46],["G0846","their",47,52],["G3962","fathers",53,60],["G1722","in",61,63],["G2250","the day",64,71],["G1949","when I took",72,83],["G0846","them",84,88],["G3450","by the hand",89,100],["G5495","by the hand",89,100],["G1806","to lead",101,108],["G0846","them",109,113],["G1537","out of",114,120],["G1093","the land",121,129],["G0125","of Egypt",130,138],["G3754","because",140,147],["G0846","they",148,152],["G1696","continued",153,162],["G3756","not",163,166],["G1722","in",167,169],["G3450","my",170,172],["G1242","covenant",173,181],["G2504","and I",183,188],["G0272","regarded",189,197],["G0846","them",198,202],["G0272","not",203,206],["G3004","saith",208,213],["G2962","the Lord",214,222]]},"8:10":{"text":"For this is the covenant that I will make with the house of Israel after those days, saith the Lord; I will put my laws into their mind, and write them in their hearts: and I will be to them a God, and they shall be to me a people:","words":[["G3754","For",0,3],["G3778","this",4,8],["G1242","is the covenant",9,24],["G3739","that",25,29],["G1303","I will make",30,41],["G3624","with the house",42,56],["G2474","of Israel",57,66],["G3326","after",67,72],["G1565","those",73,78],["G2250","days",79,83],["G3004","saith",85,90],["G2962","the Lord",91,99],["G1325","I will put",101,111],["G3450","my",112,114],["G3551","laws",115,119],["G1519","into",120,124],["G0846","their",125,130],["G1271","mind",131,135],["G2532","and",137,140],["G1924","write",141,146],["G0846","them",147,151],["G1909","in",152,154],["G0846","their",155,160],["G2588","hearts",161,167],["G2532","and",169,172],["G2071","I will be",173,182],["G1519","to",183,185],["G0846","them",186,190],["G2316","a God",191,196],["G2532","and",198,201],["G0846","they",202,206],["G2071","shall be",207,215],["G1519","to",216,218],["G3427","me",219,221],["G2992","a people",222,230]]},"8:11":{"text":"And they shall not teach every man his neighbour, and every man his brother, saying, Know the Lord: for all shall know me, from the least to the greatest.","words":[["G2532","And",0,3],["G1321","they shall",4,14],["G3364","not",15,18],["G1321","teach",19,24],["G1538","every man",25,34],["G0846","his",35,38],["G4139","neighbour",39,48],["G2532","and",50,53],["G1538","every man",54,63],["G0846","his",64,67],["G0080","brother",68,75],["G3004","saying",77,83],["G1097","Know",85,89],["G2962","the Lord",90,98],["G3754","for",100,103],["G3956","all",104,107],["G1492","shall know",108,118],["G3165","me",119,121],["G0575","from",123,127],["G3398","the least",128,137],["G0846","the least",128,137],["G2193","to",138,140],["G3173","the greatest",141,153],["G0846","the greatest",141,153]]},"8:12":{"text":"For I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more.","words":[["G3754","For",0,3],["G2071","I will be",4,13],["G2436","merciful",14,22],["G0846","to their",23,31],["G0093","unrighteousness",32,47],["G2532","and",49,52],["G0846","their",53,58],["G0266","sins",59,63],["G2532","and",64,67],["G0846","their",68,73],["G0458","iniquities",74,84],["G3415","will I remember",85,100],["G3364","no",101,103],["G2089","more",104,108]]},"8:13":{"text":"In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away.","words":[["G1722","In",0,2],["G3004","that he saith",3,16],["G2537","A new",18,23],["G3822","covenant, he hath made",24,46],["G4413","the first",47,56],["G3822","old",57,60],["G1161","Now",62,65],["G3822","that which decayeth",66,85],["G2532","and",86,89],["G1095","waxeth old",90,100],["G1451","is ready",101,109],["G0854","to vanish away",110,124]]},"9:1":{"text":"Then verily the first covenant had also ordinances of divine service, and a worldly sanctuary.","words":[["G3767","Then",0,4],["G3303","verily",5,11],["G4413","the first",12,21],["G2192","covenant had",22,34],["G2532","also",35,39],["G1345","ordinances",40,50],["G2999","of divine service",51,68],["G5037","and",70,73],["G2886","a worldly",74,83],["G0039","sanctuary",84,93]]},"9:2":{"text":"For there was a tabernacle made; the first, wherein was the candlestick, and the table, and the shewbread; which is called the sanctuary.","words":[["G1063","For",0,3],["G2680","there was",4,13],["G4633","a tabernacle",14,26],["G2680","made",27,31],["G4413","the first",33,42],["G1722","wherein",44,51],["G3739","wherein",44,51],["G5037","wherein",44,51],["G3087","was the candlestick",52,71],["G2532","and",73,76],["G5132","the table",77,86],["G2532","and",88,91],["G4286","the shewbread",92,105],["G0740","the shewbread",92,105],["G3748","which",107,112],["G3004","is called",113,122],["G0039","the sanctuary",123,136]]},"9:3":{"text":"And after the second veil, the tabernacle which is called the Holiest of all;","words":[["G1161","And",0,3],["G3326","after",4,9],["G1208","the second",10,20],["G2665","veil",21,25],["G4633","the tabernacle",27,41],["G3588","which",42,47],["G3004","is called",48,57],["G0039","the Holiest of all",58,76],["G0039","the Holiest of all",58,76]]},"9:4":{"text":"Which had the golden censer, and the ark of the covenant overlaid round about with gold, wherein was the golden pot that had manna, and Aaron's rod that budded, and the tables of the covenant;","words":[["G2192","Which had",0,9],["G5552","the golden",10,20],["G2369","censer",21,27],["G2532","and",29,32],["G2787","the ark",33,40],["G1242","of the covenant",41,56],["G4028","overlaid",57,65],["G3840","round about",66,77],["G5553","with gold",78,87],["G1722","wherein",89,96],["G3739","wherein",89,96],["G5552","was the golden",97,111],["G4713","pot",112,115],["G2192","that had",116,124],["G3131","manna",125,130],["G2532","and",132,135],["G0002","Aaron's",136,143],["G4464","rod",144,147],["G0985","that budded",148,159],["G2532","and",161,164],["G4109","the tables",165,175],["G1242","of the covenant",176,191]]},"9:5":{"text":"And over it the cherubims of glory shadowing the mercyseat; of which we cannot now speak particularly.","words":[["G1161","And",0,3],["G5231","over",4,8],["G0846","it",9,11],["G5502","the cherubims",12,25],["G1391","of glory",26,34],["G2683","shadowing",35,44],["G2435","the mercyseat",45,58],["G4012","of",60,62],["G3739","which",63,68],["G3756","we cannot",69,78],["G2076","we cannot",69,78],["G3568","now",79,82],["G3004","speak",83,88],["G2596","particularly",89,101],["G3313","particularly",89,101]]},"9:6":{"text":"Now when these things were thus ordained, the priests went always into the first tabernacle, accomplishing the service of God.","words":[["G1161","Now",0,3],["G5130","when these things",4,21],["G2680","were",22,26],["G3779","thus",27,31],["G2680","ordained",32,40],["G2409","the priests",42,53],["G1524","went",54,58],["G1275","always",59,65],["G1519","into",66,70],["G3303","into",66,70],["G4413","the first",71,80],["G4633","tabernacle",81,91],["G2005","accomplishing",93,106],["G2999","the service",107,118]]},"9:7":{"text":"But into the second went the high priest alone once every year, not without blood, which he offered for himself, and for the errors of the people:","words":[["G1161","But",0,3],["G1519","into",4,8],["G1208","the second",9,19],["G0749","went the high priest",20,40],["G3441","alone",41,46],["G0530","once",47,51],["G1763","every year",52,62],["G3756","not",64,67],["G5565","without",68,75],["G0129","blood",76,81],["G3739","which",83,88],["G4374","he offered",89,99],["G5228","for",100,103],["G1438","himself",104,111],["G2532","and",113,116],["G0051","for the errors",117,131],["G2992","of the people",132,145]]},"9:8":{"text":"The Holy Ghost this signifying, that the way into the holiest of all was not yet made manifest, while as the first tabernacle was yet standing:","words":[["G0040","The Holy",0,8],["G4151","Ghost",9,14],["G5124","this",15,19],["G1213","signifying",20,30],["G3598","that the way",32,44],["G0039","into the holiest of all",45,68],["G5319","was",69,72],["G3380","not yet",73,80],["G5319","made manifest",81,94],["G4413","while as the first",96,114],["G4633","tabernacle",115,125],["G2192","was",126,129],["G2089","yet",130,133],["G4714","standing",134,142]]},"9:9":{"text":"Which was a figure for the time then present, in which were offered both gifts and sacrifices, that could not make him that did the service perfect, as pertaining to the conscience;","words":[["G3748","Which",0,5],["G3850","was a figure",6,18],["G1519","for",19,22],["G2540","the time",23,31],["G1764","then present",32,44],["G2596","in",46,48],["G3739","which",49,54],["G4374","were offered",55,67],["G5037","both",68,72],["G1435","gifts",73,78],["G2532","and",79,82],["G2378","sacrifices",83,93],["G1410","that could",95,105],["G3361","not",106,109],["G5048","make",110,114],["G3000","him that did the service",115,139],["G5048","perfect",140,147],["G2596","as pertaining to",149,165],["G4893","the conscience",166,180]]},"9:10":{"text":"Which stood only in meats and drinks, and divers washings, and carnal ordinances, imposed on them until the time of reformation.","words":[["G3440","Which stood only",0,16],["G1909","in",17,19],["G1033","meats",20,25],["G2532","and",26,29],["G4188","drinks",30,36],["G2532","and",38,41],["G1313","divers",42,48],["G0909","washings",49,57],["G2532","and",59,62],["G4561","carnal",63,69],["G1345","ordinances",70,80],["G1945","imposed",82,89],["G3360","on them until",90,103],["G2540","the time",104,112],["G1357","of reformation",113,127]]},"9:11":{"text":"But Christ being come an high priest of good things to come, by a greater and more perfect tabernacle, not made with hands, that is to say, not of this building;","words":[["G1161","But",0,3],["G5547","Christ",4,10],["G3854","being come",11,21],["G0749","an high priest",22,36],["G0018","of good things",37,51],["G3195","to come",52,59],["G1223","by",61,63],["G3187","a greater",64,73],["G2532","and",74,77],["G5046","more perfect",78,90],["G4633","tabernacle",91,101],["G3756","not",103,106],["G5499","made with hands",107,122],["G5123","that is to say",124,138],["G3756","not",140,143],["G5026","of this",144,151],["G2937","building",152,160]]},"9:12":{"text":"Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption for us.","words":[["G3761","Neither",0,7],["G1223","by",8,10],["G0129","the blood",11,20],["G5131","of goats",21,29],["G2532","and",30,33],["G3448","calves",34,40],["G1161","but",42,45],["G1223","by",46,48],["G2398","his own",49,56],["G0129","blood",57,62],["G1525","he entered in",63,76],["G2178","once",77,81],["G1519","into",82,86],["G0039","the holy place",87,101],["G2147","having obtained",103,118],["G0166","eternal",119,126],["G3085","redemption",127,137]]},"9:13":{"text":"For if the blood of bulls and of goats, and the ashes of an heifer sprinkling the unclean, sanctifieth to the purifying of the flesh:","words":[["G1063","For",0,3],["G1487","if",4,6],["G0129","the blood",7,16],["G5022","of bulls",17,25],["G2532","and",26,29],["G5131","of goats",30,38],["G2532","and",40,43],["G4700","the ashes",44,53],["G1151","of an heifer",54,66],["G4472","sprinkling",67,77],["G2840","the unclean",78,89],["G0037","sanctifieth",91,102],["G4314","to",103,105],["G2514","the purifying",106,119],["G4561","of the flesh",120,132]]},"9:14":{"text":"How much more shall the blood of Christ, who through the eternal Spirit offered himself without spot to God, purge your conscience from dead works to serve the living God?","words":[["G4214","How much",0,8],["G3123","more",9,13],["G2511","shall",14,19],["G0129","the blood",20,29],["G5547","of Christ",30,39],["G3739","who",41,44],["G1223","through",45,52],["G0166","the eternal",53,64],["G4151","Spirit",65,71],["G4374","offered",72,79],["G1438","himself",80,87],["G0299","without spot",88,100],["G2316","to God",101,107],["G2511","purge",109,114],["G5216","your",115,119],["G4893","conscience",120,130],["G0575","from",131,135],["G3498","dead",136,140],["G2041","works",141,146],["G1519","to",147,149],["G3000","serve",150,155],["G2198","the living",156,166],["G2316","God",167,170]]},"9:15":{"text":"And for this cause he is the mediator of the new testament, that by means of death, for the redemption of the transgressions that were under the first testament, they which are called might receive the promise of eternal inheritance.","words":[["G2532","And",0,3],["G5124","for this",4,12],["G1223","cause",13,18],["G2076","he is",19,24],["G3316","the mediator",25,37],["G2537","of the new",38,48],["G1242","testament",49,58],["G3704","that",60,64],["G1096","by means",65,73],["G2288","of death",74,82],["G1519","for",84,87],["G0629","the redemption",88,102],["G3847","of the transgressions",103,124],["G1909","that were under",125,140],["G4413","the first",141,150],["G1242","testament",151,160],["G2564","they which are called",162,183],["G2983","might receive",184,197],["G1860","the promise",198,209],["G0166","of eternal",210,220],["G2817","inheritance",221,232]]},"9:16":{"text":"For where a testament is, there must also of necessity be the death of the testator.","words":[["G1063","For",0,3],["G3699","where",4,9],["G1242","a testament",10,21],["G0318","is, there must also of necessity",22,54],["G5342","be",55,57],["G2288","the death",58,67],["G1303","of the testator",68,83]]},"9:17":{"text":"For a testament is of force after men are dead: otherwise it is of no strength at all while the testator liveth.","words":[["G1063","For",0,3],["G1242","a testament",4,15],["G0949","is of force",16,27],["G1909","after",28,33],["G3498","men are dead",34,46],["G1893","otherwise",48,57],["G2480","it is of",58,66],["G3379","no",67,69],["G2480","strength",70,78],["G3379","at all",79,85],["G3753","while",86,91],["G1303","the testator",92,104],["G2198","liveth",105,111]]},"9:18":{"text":"Whereupon neither the first testament was dedicated without blood.","words":[["G3606","Whereupon",0,9],["G3761","neither",10,17],["G4413","the first",18,27],["G1457","testament was dedicated",28,51],["G5565","without",52,59],["G0129","blood",60,65]]},"9:19":{"text":"For when Moses had spoken every precept to all the people according to the law, he took the blood of calves and of goats, with water, and scarlet wool, and hyssop, and sprinkled both the book, and all the people,","words":[["G1063","For",0,3],["G5259","when",4,8],["G3475","Moses",9,14],["G2980","had spoken",15,25],["G3956","every",26,31],["G1785","precept",32,39],["G3956","to all",40,46],["G2992","the people",47,57],["G2596","according",58,67],["G3551","to the law",68,78],["G2983","he took",80,87],["G0129","the blood",88,97],["G3448","of calves",98,107],["G2532","and",108,111],["G5131","of goats",112,120],["G3326","with",122,126],["G5204","water",127,132],["G2532","and",134,137],["G2847","scarlet",138,145],["G2053","wool",146,150],["G2532","and",152,155],["G5301","hyssop",156,162],["G4472","and sprinkled",164,177],["G5037","both",178,182],["G0975","the book",183,191],["G0846","the book",183,191],["G2532","and",193,196],["G3956","all",197,200],["G2992","the people",201,211]]},"9:20":{"text":"Saying, This is the blood of the testament which God hath enjoined unto you.","words":[["G3004","Saying",0,6],["G5124","This",8,12],["G0129","is the blood",13,25],["G1242","of the testament",26,42],["G3739","which",43,48],["G2316","God",49,52],["G1781","hath enjoined",53,66],["G4314","unto",67,71],["G5209","you",72,75]]},"9:21":{"text":"Moreover he sprinkled with blood both the tabernacle, and all the vessels of the ministry.","words":[["G1161","Moreover",0,8],["G3668","Moreover",0,8],["G4472","he sprinkled",9,21],["G0129","with blood",22,32],["G2532","both",33,37],["G4633","the tabernacle",38,52],["G2532","and",54,57],["G3956","all",58,61],["G4632","the vessels",62,73],["G3009","of the ministry",74,89]]},"9:22":{"text":"And almost all things are by the law purged with blood; and without shedding of blood is no remission.","words":[["G2532","And",0,3],["G4975","almost",4,10],["G3956","all things",11,21],["G2511","are",22,25],["G2596","by",26,28],["G3551","the law",29,36],["G2511","purged",37,43],["G1722","with",44,48],["G0129","blood",49,54],["G2532","and",56,59],["G5565","without",60,67],["G0130","shedding of blood",68,85],["G1096","is",86,88],["G3756","no",89,91],["G0859","remission",92,101]]},"9:23":{"text":"It was therefore necessary that the patterns of things in the heavens should be purified with these; but the heavenly things themselves with better sacrifices than these.","words":[["G3767","It was therefore",0,16],["G0318","necessary",17,26],["G5262","that the patterns",27,44],["G3303","of things",45,54],["G1722","in",55,57],["G3772","the heavens",58,69],["G2511","should be purified",70,88],["G5125","with these",89,99],["G1161","but",101,104],["G2032","the heavenly things",105,124],["G0846","themselves",125,135],["G2909","with better",136,147],["G2378","sacrifices",148,158],["G3844","than",159,163],["G5025","these",164,169]]},"9:24":{"text":"For Christ is not entered into the holy places made with hands, which are the figures of the true; but into heaven itself, now to appear in the presence of God for us:","words":[["G1063","For",0,3],["G5547","Christ",4,10],["G1525","is",11,13],["G3756","not",14,17],["G1525","entered",18,25],["G1519","into",26,30],["G0039","the holy places",31,46],["G5499","made with hands",47,62],["G0499","which are the figures",64,85],["G0228","of the true",86,97],["G0235","but",99,102],["G1519","into",103,107],["G3772","heaven",108,114],["G0846","itself",115,121],["G3568","now",123,126],["G1718","to appear",127,136],["G4383","in the presence",137,152],["G2316","of God",153,159],["G5228","for",160,163],["G2257","us",164,166]]},"9:25":{"text":"Nor yet that he should offer himself often, as the high priest entereth into the holy place every year with blood of others;","words":[["G3761","Nor",0,3],["G2443","yet that",4,12],["G4374","he should offer",13,28],["G1438","himself",29,36],["G4178","often",37,42],["G5618","as",44,46],["G0749","the high priest",47,62],["G1525","entereth",63,71],["G1519","into",72,76],["G0039","the holy place",77,91],["G2596","every",92,97],["G1763","year",98,102],["G1722","with",103,107],["G0129","blood",108,113],["G0245","of others",114,123]]},"9:26":{"text":"For then must he often have suffered since the foundation of the world: but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself.","words":[["G1893","For then",0,8],["G1163","must",9,13],["G0846","he",14,16],["G4178","often",17,22],["G3958","have suffered",23,36],["G0575","since",37,42],["G2602","the foundation",43,57],["G2889","of the world",58,70],["G1161","but",72,75],["G3568","now",76,79],["G0530","once",80,84],["G1909","in",85,87],["G4930","the end",88,95],["G0165","of the world",96,108],["G5319","hath he appeared",109,125],["G1519","to",126,128],["G0115","put away",129,137],["G0266","sin",138,141],["G1223","by",142,144],["G2378","the sacrifice",145,158],["G0846","of himself",159,169]]},"9:27":{"text":"And as it is appointed unto men once to die, but after this the judgment:","words":[["G2532","And",0,3],["G2596","as",4,6],["G3745","as",4,6],["G0606","it is appointed",7,22],["G0444","unto men",23,31],["G0530","once",32,36],["G0599","to die",37,43],["G1161","but",45,48],["G3326","after",49,54],["G5124","this",55,59],["G2920","the judgment",60,72]]},"9:28":{"text":"So Christ was once offered to bear the sins of many; and unto them that look for him shall he appear the second time without sin unto salvation.","words":[["G3779","So",0,2],["G5547","Christ",3,9],["G0530","was once",10,18],["G4374","offered",19,26],["G1519","to",27,29],["G0399","bear",30,34],["G0266","the sins",35,43],["G4183","of many",44,51],["G0553","and unto them that look",53,76],["G0846","for him",77,84],["G3700","shall he appear",85,100],["G1537","shall he appear",85,100],["G1208","the second time",101,116],["G5565","without",117,124],["G0266","sin",125,128],["G1519","unto",129,133],["G4991","salvation",134,143]]},"10:1":{"text":"For the law having a shadow of good things to come, and not the very image of the things, can never with those sacrifices which they offered year by year continually make the comers thereunto perfect.","words":[["G1063","For",0,3],["G3551","the law",4,11],["G2192","having",12,18],["G4639","a shadow",19,27],["G0018","of good things",28,42],["G3195","to come",43,50],["G3756","and not",52,59],["G0846","the very",60,68],["G1504","image",69,74],["G4229","of the things",75,88],["G1410","can",90,93],["G3763","never",94,99],["G0846","with those",100,110],["G2378","sacrifices",111,121],["G3739","which",122,127],["G4374","they offered",128,140],["G2596","year by year",141,153],["G1763","year by year",141,153],["G1519","continually",154,165],["G1336","continually",154,165],["G5048","make",166,170],["G4334","the comers thereunto",171,191],["G5048","perfect",192,199]]},"10:2":{"text":"For then would they not have ceased to be offered? because that the worshippers once purged should have had no more conscience of sins.","words":[["G1893","For then",0,8],["G0302","would they",9,19],["G3756","not",20,23],["G3973","have ceased",24,35],["G4374","to be offered",36,49],["G1223","because",51,58],["G3000","that the worshippers",59,79],["G0530","once",80,84],["G2508","purged",85,91],["G2192","should have had",92,107],["G3367","no",108,110],["G2089","more",111,115],["G4893","conscience",116,126],["G0266","of sins",127,134]]},"10:3":{"text":"But in those sacrifices there is a remembrance again made of sins every year.","words":[["G0235","But",0,3],["G1722","in",4,6],["G0846","those",7,12],["G0364","sacrifices there is a remembrance again",13,52],["G0266","made of sins",53,65],["G2596","every",66,71],["G1763","year",72,76]]},"10:4":{"text":"For it is not possible that the blood of bulls and of goats should take away sins.","words":[["G1063","For",0,3],["G0102","it is not possible",4,22],["G0129","that the blood",23,37],["G5022","of bulls",38,46],["G2532","and",47,50],["G5131","of goats",51,59],["G0851","should take away",60,76],["G0266","sins",77,81]]},"10:5":{"text":"Wherefore when he cometh into the world, he saith, Sacrifice and offering thou wouldest not, but a body hast thou prepared me:","words":[["G1352","Wherefore",0,9],["G1525","when he cometh",10,24],["G1519","into",25,29],["G2889","the world",30,39],["G3004","he saith",41,49],["G2378","Sacrifice",51,60],["G2532","and",61,64],["G4376","offering",65,73],["G2309","thou wouldest",74,87],["G3756","not",88,91],["G1161","but",93,96],["G4983","a body",97,103],["G2675","hast thou prepared",104,122],["G3427","me",123,125]]},"10:6":{"text":"In burnt offerings and sacrifices for sin thou hast had no pleasure.","words":[["G3646","In burnt offerings",0,18],["G2532","and",19,22],["G4012","sacrifices for",23,37],["G0266","sin",38,41],["G2106","thou hast had",42,55],["G3756","no",56,58],["G2106","pleasure",59,67]]},"10:7":{"text":"Then said I, Lo, I come (in the volume of the book it is written of me,) to do thy will, O God.","words":[["G5119","Then",0,4],["G2036","said I",5,11],["G2400","Lo",13,15],["G2240","I come",17,23],["G1722","(in",24,27],["G2777","the volume",28,38],["G0975","of the book",39,50],["G1125","it is written",51,64],["G4012","of",65,67],["G1700","me",68,70],["G4160",") to do",71,78],["G4675","thy",79,82],["G2307","will",83,87],["G2316","O God",89,94]]},"10:8":{"text":"Above when he said, Sacrifice and offering and burnt offerings and offering for sin thou wouldest not, neither hadst pleasure therein; which are offered by the law;","words":[["G0511","Above",0,5],["G3004","when he said",6,18],["G3754","",-1,-1],["G2378","Sacrifice",20,29],["G2532","and",30,33],["G4376","offering",34,42],["G2532","and",43,46],["G3646","burnt offerings",47,62],["G2532","and",63,66],["G4012","offering for",67,79],["G0266","sin",80,83],["G2309","thou wouldest",84,97],["G3756","not",98,101],["G3761","neither",103,110],["G2106","hadst pleasure",111,125],["G3748","therein; which",126,140],["G4374","are offered",141,152],["G2596","by",153,155],["G3551","the law",156,163]]},"10:9":{"text":"Then said he, Lo, I come to do thy will, O God. He taketh away the first, that he may establish the second.","words":[["G5119","Then",0,4],["G2046","said he",5,12],["G2400","Lo",14,16],["G2240","I come",18,24],["G4160","to do",25,30],["G4675","thy",31,34],["G2307","will",35,39],["G2316","O God",41,46],["G0337","He taketh away",48,62],["G4413","the first",63,72],["G2443","that",74,78],["G2476","he may establish",79,95],["G1208","the second",96,106]]},"10:10":{"text":"By the which will we are sanctified through the offering of the body of Jesus Christ once for all.","words":[["G1722","By",0,2],["G3739","the which",3,12],["G2307","will",13,17],["G2070","we are",18,24],["G0037","sanctified",25,35],["G1223","through",36,43],["G4376","the offering",44,56],["G4983","of the body",57,68],["G2424","of Jesus",69,77],["G5547","Christ",78,84],["G2178","once",85,89]]},"10:11":{"text":"And every priest standeth daily ministering and offering oftentimes the same sacrifices, which can never take away sins:","words":[["G2532","And",0,3],["G3303","And",0,3],["G3956","every",4,9],["G2409","priest",10,16],["G2476","standeth",17,25],["G2596","daily",26,31],["G2250","daily",26,31],["G3008","ministering",32,43],["G2532","and",44,47],["G4374","offering",48,56],["G4178","oftentimes",57,67],["G0846","the same",68,76],["G2378","sacrifices",77,87],["G3748","which",89,94],["G1410","can",95,98],["G3763","never",99,104],["G4014","take away",105,114],["G0266","sins",115,119]]},"10:12":{"text":"But this man, after he had offered one sacrifice for sins for ever, sat down on the right hand of God;","words":[["G1161","But",0,3],["G0846","this man",4,12],["G4374","after he had offered",14,34],["G3391","one",35,38],["G2378","sacrifice",39,48],["G5228","for",49,52],["G0266","sins",53,57],["G1519","for",58,61],["G1336","ever",62,66],["G2523","sat down",68,76],["G1722","on",77,79],["G1188","the right hand",80,94],["G2316","of God",95,101]]},"10:13":{"text":"From henceforth expecting till his enemies be made his footstool.","words":[["G3063","From henceforth",0,15],["G1551","expecting",16,25],["G2193","till",26,30],["G0846","his",31,34],["G2190","enemies",35,42],["G5087","be made",43,50],["G0846","his",51,54],["G5286","footstool",55,64],["G4228","footstool",55,64]]},"10:14":{"text":"For by one offering he hath perfected for ever them that are sanctified.","words":[["G1063","For",0,3],["G3391","by one",4,10],["G4376","offering",11,19],["G5048","he hath perfected",20,37],["G1519","for",38,41],["G1336","ever",42,46],["G0037","them that are sanctified",47,71]]},"10:15":{"text":"Whereof the Holy Ghost also is a witness to us: for after that he had said before,","words":[["G1161","Whereof",0,7],["G0040","the Holy",8,16],["G4151","Ghost",17,22],["G2532","also",23,27],["G3140","is a witness",28,40],["G2254","to us",41,46],["G1063","for",48,51],["G3326","after",52,57],["G4280","that he had said before",58,81]]},"10:16":{"text":"This is the covenant that I will make with them after those days, saith the Lord, I will put my laws into their hearts, and in their minds will I write them;","words":[["G3778","This",0,4],["G1242","is the covenant",5,20],["G3739","that",21,25],["G1303","I will make",26,37],["G4314","with",38,42],["G0846","them",43,47],["G3326","after",48,53],["G1565","those",54,59],["G2250","days",60,64],["G3004","saith",66,71],["G2962","the Lord",72,80],["G1325","I will put",82,92],["G3450","my",93,95],["G3551","laws",96,100],["G1909","into",101,105],["G0846","their",106,111],["G2588","hearts",112,118],["G2532","and",120,123],["G1909","in",124,126],["G0846","their",127,132],["G1271","minds",133,138],["G1924","will I write",139,151],["G0846","them",152,156]]},"10:17":{"text":"And their sins and iniquities will I remember no more.","words":[["G2532","And",0,3],["G0846","their",4,9],["G0266","sins",10,14],["G2532","and",15,18],["G0458","iniquities",19,29],["G0846","iniquities",19,29],["G3415","will I remember",30,45],["G3364","no",46,48],["G2089","more",49,53]]},"10:18":{"text":"Now where remission of these is, there is no more offering for sin.","words":[["G1161","Now",0,3],["G3699","where",4,9],["G0859","remission",10,19],["G5130","of these",20,28],["G3765","is, there is no more",29,49],["G4376","offering",50,58],["G4012","for",59,62],["G0266","sin",63,66]]},"10:19":{"text":"Having therefore, brethren, boldness to enter into the holiest by the blood of Jesus,","words":[["G2192","Having",0,6],["G3767","therefore",7,16],["G0080","brethren",18,26],["G3954","boldness",28,36],["G1519","to",37,39],["G1529","enter",40,45],["G0039","into the holiest",46,62],["G1722","by",63,65],["G0129","the blood",66,75],["G2424","of Jesus",76,84]]},"10:20":{"text":"By a new and living way, which he hath consecrated for us, through the veil, that is to say, his flesh;","words":[["G4372","By a new",0,8],["G2532","and",9,12],["G2198","living",13,19],["G3598","way",20,23],["G3739","which",25,30],["G1457","he hath consecrated",31,50],["G2254","for us",51,57],["G1223","through",59,66],["G2665","the veil",67,75],["G5123","that is to say",77,91],["G0846","his",93,96],["G4561","flesh",97,102]]},"10:21":{"text":"And having an high priest over the house of God;","words":[["G2532","And",0,3],["G3173","having an high",4,18],["G2409","priest",19,25],["G1909","over",26,30],["G3624","the house",31,40],["G2316","of God",41,47]]},"10:22":{"text":"Let us draw near with a true heart in full assurance of faith, having our hearts sprinkled from an evil conscience, and our bodies washed with pure water.","words":[["G4334","Let us draw near",0,16],["G3326","with",17,21],["G0228","a true",22,28],["G2588","heart",29,34],["G1722","in",35,37],["G4136","full assurance",38,52],["G4102","of faith",53,61],["G4472","having",63,69],["G2588","our hearts",70,80],["G4472","sprinkled",81,90],["G0575","from",91,95],["G4190","an evil",96,103],["G4893","conscience",104,114],["G2532","and",116,119],["G4983","our bodies",120,130],["G3068","washed",131,137],["G2513","with pure",138,147],["G5204","water",148,153]]},"10:23":{"text":"Let us hold fast the profession of our faith without wavering; (for he is faithful that promised;)","words":[["G2722","Let us hold fast",0,16],["G3671","the profession",17,31],["G1680","of our faith",32,44],["G0186","without wavering",45,61],["G1063","(for",63,67],["G4103","he is faithful",68,82],["G1861","that promised",83,96]]},"10:24":{"text":"And let us consider one another to provoke unto love and to good works:","words":[["G2532","And",0,3],["G2657","let us consider",4,19],["G0240","one another",20,31],["G1519","to",32,34],["G3948","provoke",35,42],["G0026","unto love",43,52],["G2532","and",53,56],["G2570","to good",57,64],["G2041","works",65,70]]},"10:25":{"text":"Not forsaking the assembling of ourselves together, as the manner of some is; but exhorting one another: and so much the more, as ye see the day approaching.","words":[["G3361","Not",0,3],["G1459","forsaking",4,13],["G1997","the assembling",14,28],["G1438","of ourselves",29,41],["G1997","together",42,50],["G2531","as",52,54],["G1485","the manner",55,65],["G5100","of some",66,73],["G0235","is; but",74,81],["G3870","exhorting",82,91],["G2532","one another: and",92,108],["G5118","so much",109,116],["G3123","the more",117,125],["G3745","as",127,129],["G0991","ye see",130,136],["G2250","the day",137,144],["G1448","approaching",145,156]]},"10:26":{"text":"For if we sin wilfully after that we have received the knowledge of the truth, there remaineth no more sacrifice for sins,","words":[["G1063","For",0,3],["G2257","if we",4,9],["G0264","sin",10,13],["G1596","wilfully",14,22],["G3326","after",23,28],["G2983","that we have received",29,50],["G1922","the knowledge",51,64],["G0225","of the truth",65,77],["G0620","there remaineth",79,94],["G3765","no more",95,102],["G2378","sacrifice",103,112],["G4012","for",113,116],["G0266","sins",117,121]]},"10:27":{"text":"But a certain fearful looking for of judgment and fiery indignation, which shall devour the adversaries.","words":[["G1161","But",0,3],["G5100","a certain",4,13],["G5398","fearful",14,21],["G1561","looking for",22,33],["G2920","of judgment",34,45],["G2532","and",46,49],["G4442","fiery",50,55],["G2205","indignation",56,67],["G3195","which shall",69,80],["G2068","devour",81,87],["G5227","the adversaries",88,103]]},"10:28":{"text":"He that despised Moses' law died without mercy under two or three witnesses:","words":[["G5100","He",0,2],["G0114","that despised",3,16],["G3475","Moses'",17,23],["G3551","law",24,27],["G0599","died",28,32],["G5565","without",33,40],["G3628","mercy",41,46],["G1909","under",47,52],["G1417","two",53,56],["G2228","or",57,59],["G5140","three",60,65],["G3144","witnesses",66,75]]},"10:29":{"text":"Of how much sorer punishment, suppose ye, shall he be thought worthy, who hath trodden under foot the Son of God, and hath counted the blood of the covenant, wherewith he was sanctified, an unholy thing, and hath done despite unto the Spirit of grace?","words":[["G4214","Of how much",0,11],["G5501","sorer",12,17],["G5098","punishment",18,28],["G1380","suppose ye",30,40],["G0515","shall he be thought worthy",42,68],["G3588","who",70,73],["G2662","hath trodden under foot",74,97],["G5207","the Son",98,105],["G2316","of God",106,112],["G2532","and",114,117],["G2233","hath counted",118,130],["G0129","the blood",131,140],["G1242","of the covenant",141,156],["G3739","wherewith",158,167],["G1722","wherewith",158,167],["G0037","he was sanctified",168,185],["G2839","an unholy thing",187,202],["G2532","and",204,207],["G1796","hath done despite",208,225],["G4151","unto the Spirit",226,241],["G5485","of grace",242,250]]},"10:30":{"text":"For we know him that hath said, Vengeance belongeth unto me, I will recompense, saith the Lord. And again, The Lord shall judge his people.","words":[["G1063","For",0,3],["G1492","we know",4,11],["G2036","him that hath said",12,30],["G1557","Vengeance",32,41],["G1698","belongeth unto me",42,59],["G1473","I",61,62],["G0467","will recompense",63,78],["G3004","saith",80,85],["G2962","the Lord",86,94],["G2532","And",96,99],["G3825","again",100,105],["G2962","The Lord",107,115],["G2919","shall judge",116,127],["G0846","his",128,131],["G2992","people",132,138]]},"10:31":{"text":"It is a fearful thing to fall into the hands of the living God.","words":[["G5398","It is a fearful thing",0,21],["G1706","to fall",22,29],["G1519","into",30,34],["G5495","the hands",35,44],["G2198","of the living",45,58],["G2316","God",59,62]]},"10:32":{"text":"But call to remembrance the former days, in which, after ye were illuminated, ye endured a great fight of afflictions;","words":[["G1161","But",0,3],["G0363","call to remembrance",4,23],["G4386","the former",24,34],["G2250","days",35,39],["G1722","in",41,43],["G3739","which",44,49],["G5461","after ye were illuminated",51,76],["G5278","ye endured",78,88],["G4183","a great",89,96],["G0119","fight",97,102],["G3804","of afflictions",103,117]]},"10:33":{"text":"Partly, whilst ye were made a gazingstock both by reproaches and afflictions; and partly, whilst ye became companions of them that were so used.","words":[["G5124","Partly",0,6],["G3303","Partly",0,6],["G2301","whilst ye were made a gazingstock",8,41],["G5037","both",42,46],["G3680","by reproaches",47,60],["G2532","and",61,64],["G2347","afflictions",65,76],["G1161","and",78,81],["G5124","partly",82,88],["G1096","whilst ye became",90,106],["G2844","companions",107,117],["G0390","of them that were",118,135],["G3779","so",136,138],["G0390","used",139,143]]},"10:34":{"text":"For ye had compassion of me in my bonds, and took joyfully the spoiling of your goods, knowing in yourselves that ye have in heaven a better and an enduring substance.","words":[["G2532","For",0,3],["G1063","For",0,3],["G4834","ye had compassion",4,21],["G3450","of me in my",22,33],["G1199","bonds",34,39],["G2532","and",41,44],["G4327","took",45,49],["G3326","joyfully",50,58],["G5479","joyfully",50,58],["G0724","the spoiling",59,71],["G5216","of your",72,79],["G5224","goods",80,85],["G1097","knowing",87,94],["G1722","in",95,97],["G1438","yourselves",98,108],["G2192","that ye have",109,121],["G1722","in",122,124],["G3772","heaven",125,131],["G2909","a better",132,140],["G2532","and",141,144],["G3306","an enduring",145,156],["G5223","substance",157,166]]},"10:35":{"text":"Cast not away therefore your confidence, which hath great recompence of reward.","words":[["G0577","Cast",0,4],["G3361","not",5,8],["G0577","away",9,13],["G3767","therefore",14,23],["G5216","your",24,28],["G3954","confidence",29,39],["G3748","which",41,46],["G2192","hath",47,51],["G3173","great",52,57],["G3405","recompence of reward",58,78]]},"10:36":{"text":"For ye have need of patience, that, after ye have done the will of God, ye might receive the promise.","words":[["G1063","For",0,3],["G2192","ye have",4,11],["G5532","need",12,16],["G5281","of patience",17,28],["G2443","that",30,34],["G4160","after ye have done",36,54],["G2307","the will",55,63],["G2316","of God",64,70],["G2865","ye might receive",72,88],["G1860","the promise",89,100]]},"10:37":{"text":"For yet a little while, and he that shall come will come, and will not tarry.","words":[["G1063","For",0,3],["G2089","yet",4,7],["G3397","a little",8,16],["G3745","while",17,22],["G3745","while",17,22],["G2064","and he that shall come",24,46],["G2240","will come",47,56],["G2532","and",58,61],["G5549","will",62,66],["G3756","not",67,70],["G5549","tarry",71,76]]},"10:38":{"text":"Now the just shall live by faith: but if any man draw back, my soul shall have no pleasure in him.","words":[["G1161","Now",0,3],["G1342","the just",4,12],["G2198","shall live",13,23],["G1537","by",24,26],["G4102","faith",27,32],["G2532","but",34,37],["G1437","if",38,40],["G5288","any man draw back",41,58],["G3450","my",60,62],["G5590","soul",63,67],["G2106","shall have",68,78],["G3756","no",79,81],["G2106","pleasure",82,90],["G1722","in",91,93],["G0846","him",94,97]]},"10:39":{"text":"But we are not of them who draw back unto perdition; but of them that believe to the saving of the soul.","words":[["G1161","But",0,3],["G2249","we",4,6],["G2070","are",7,10],["G3756","not",11,14],["G5289","of them who draw back",15,36],["G1519","unto",37,41],["G0684","perdition",42,51],["G0235","but",53,56],["G4102","of them that believe",57,77],["G1519","to",78,80],["G4047","the saving",81,91],["G5590","of the soul",92,103]]},"11:1":{"text":"Now faith is the substance of things hoped for, the evidence of things not seen.","words":[["G1161","Now",0,3],["G4102","faith",4,9],["G2076","is",10,12],["G5287","the substance",13,26],["G1679","of things hoped for",27,46],["G1650","the evidence",48,60],["G4229","of things",61,70],["G3756","not",71,74],["G0991","seen",75,79]]},"11:2":{"text":"For by it the elders obtained a good report.","words":[["G1063","For",0,3],["G1722","by",4,6],["G5026","it",7,9],["G4245","the elders",10,20],["G3140","obtained a good report",21,43]]},"11:3":{"text":"Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not made of things which do appear.","words":[["G4102","Through faith",0,13],["G3539","we understand",14,27],["G0165","that the worlds",28,43],["G2675","were framed",44,55],["G4487","by the word",56,67],["G2316","of God",68,74],["G1519","so",76,78],["G3588","that things which",79,96],["G0991","are seen",97,105],["G1096","were",106,110],["G3361","not",111,114],["G1096","made",115,119],["G1537","of",120,122],["G5316","things which do appear",123,145]]},"11:4":{"text":"By faith Abel offered unto God a more excellent sacrifice than Cain, by which he obtained witness that he was righteous, God testifying of his gifts: and by it he being dead yet speaketh.","words":[["G4102","By faith",0,8],["G0006","Abel",9,13],["G4374","offered",14,21],["G2316","unto God",22,30],["G4119","a more excellent",31,47],["G2378","sacrifice",48,57],["G3844","than",58,62],["G2535","Cain",63,67],["G1223","by",69,71],["G3739","which",72,77],["G3140","he obtained witness",78,97],["G1511","that he was",98,109],["G1342","righteous",110,119],["G2316","God",121,124],["G3140","testifying",125,135],["G1909","of",136,138],["G0846","his",139,142],["G1435","gifts",143,148],["G2532","and",150,153],["G1223","by",154,156],["G0846","it",157,159],["G0599","he being dead",160,173],["G2089","yet",174,177],["G2980","speaketh",178,186],["G2980","speaketh",178,186]]},"11:5":{"text":"By faith Enoch was translated that he should not see death; and was not found, because God had translated him: for before his translation he had this testimony, that he pleased God.","words":[["G4102","By faith",0,8],["G1802","Enoch",9,14],["G3346","was translated",15,29],["G1492","that he should",30,44],["G3361","not",45,48],["G1492","see",49,52],["G2288","death",53,58],["G2532","and",60,63],["G2147","was",64,67],["G3756","not",68,71],["G2147","found",72,77],["G1360","because",79,86],["G2316","God",87,90],["G3346","had translated",91,105],["G0846","him",106,109],["G1063","for",111,114],["G4253","before",115,121],["G0846","his",122,125],["G3331","translation",126,137],["G3140","he had this testimony",138,159],["G2100","that he pleased",161,176],["G2316","God",177,180]]},"11:6":{"text":"But without faith it is impossible to please him: for he that cometh to God must believe that he is, and that he is a rewarder of them that diligently seek him.","words":[["G1161","But",0,3],["G5565","without",4,11],["G4102","faith",12,17],["G0102","it is impossible",18,34],["G2100","to please",35,44],["G1063","him: for",45,53],["G4334","he that cometh",54,68],["G2316","to God",69,75],["G1163","must",76,80],["G4100","believe",81,88],["G3754","that",89,93],["G2076","he is",94,99],["G2532","and",101,104],["G1096","that he is",105,115],["G3406","a rewarder",116,126],["G1567","of them that diligently seek",127,155],["G0846","him",156,159]]},"11:7":{"text":"By faith Noah, being warned of God of things not seen as yet, moved with fear, prepared an ark to the saving of his house; by the which he condemned the world, and became heir of the righteousness which is by faith.","words":[["G4102","By faith",0,8],["G3575","Noah",9,13],["G5537","being warned of God",15,34],["G4012","of",35,37],["G3369","things not",38,48],["G0991","seen",49,53],["G3369","as yet",54,60],["G2125","moved with fear",62,77],["G2680","prepared",79,87],["G2787","an ark",88,94],["G1519","to",95,97],["G4991","the saving",98,108],["G0846","of his",109,115],["G3624","house",116,121],["G1223","by",123,125],["G3739","the which",126,135],["G2632","he condemned",136,148],["G2889","the world",149,158],["G2532","and",160,163],["G1096","became",164,170],["G2818","heir",171,175],["G1343","of the righteousness",176,196],["G2596","which is by",197,208],["G4102","faith",209,214]]},"11:8":{"text":"By faith Abraham, when he was called to go out into a place which he should after receive for an inheritance, obeyed; and he went out, not knowing whither he went.","words":[["G4102","By faith",0,8],["G0011","Abraham",9,16],["G2564","when he was called",18,36],["G1831","to go out",37,46],["G1519","into",47,51],["G5117","a place",52,59],["G3739","which",60,65],["G3195","he should after",66,81],["G2983","receive",82,89],["G1519","for",90,93],["G2817","an inheritance",94,108],["G5219","obeyed",110,116],["G2532","and",118,121],["G1831","he went out",122,133],["G3361","not",135,138],["G1987","knowing",139,146],["G4226","whither",147,154],["G2064","he went",155,162]]},"11:9":{"text":"By faith he sojourned in the land of promise, as in a strange country, dwelling in tabernacles with Isaac and Jacob, the heirs with him of the same promise:","words":[["G4102","By faith",0,8],["G3939","he sojourned",9,21],["G1519","in",22,24],["G1093","the land",25,33],["G1860","of promise",34,44],["G5613","as",46,48],["G0245","in a strange country",49,69],["G2730","dwelling",71,79],["G1722","in",80,82],["G4633","tabernacles",83,94],["G3326","with",95,99],["G2464","Isaac",100,105],["G2532","and",106,109],["G2384","Jacob",110,115],["G4789","the heirs with him",117,135],["G0846","of the same",136,147],["G1860","promise",148,155]]},"11:10":{"text":"For he looked for a city which hath foundations, whose builder and maker is God.","words":[["G1063","For",0,3],["G1551","he looked for",4,17],["G4172","a city",18,24],["G2192","which hath",25,35],["G2310","foundations",36,47],["G3739","whose",49,54],["G5079","builder",55,62],["G2532","and",63,66],["G1217","maker",67,72],["G2316","is God",73,79]]},"11:11":{"text":"Through faith also Sara herself received strength to conceive seed, and was delivered of a child when she was past age, because she judged him faithful who had promised.","words":[["G4102","Through faith",0,13],["G2532","also",14,18],["G4564","Sara",19,23],["G0846","herself",24,31],["G2983","received",32,40],["G1411","strength",41,49],["G1519","to",50,52],["G2602","conceive",53,61],["G4690","seed",62,66],["G2532","and",68,71],["G5088","was delivered of a child",72,96],["G3844","when she was past",97,114],["G2540","age",115,118],["G2244","age",115,118],["G1893","because",120,127],["G2233","she judged",128,138],["G4103","him faithful",139,151],["G1861","who had promised",152,168]]},"11:12":{"text":"Therefore sprang there even of one, and him as good as dead, so many as the stars of the sky in multitude, and as the sand which is by the sea shore innumerable.","words":[["G1352","Therefore",0,9],["G1080","sprang there",10,22],["G2532","even",23,27],["G0575","of",28,30],["G1520","one",31,34],["G2532","and",36,39],["G5023","him",40,43],["G3499","as good as dead",44,59],["G2531","so many as",61,71],["G0798","the stars",72,81],["G3772","of the sky",82,92],["G4128","in multitude",93,105],["G2532","and",107,110],["G5616","as",111,113],["G0285","the sand",114,122],["G3588","which",123,128],["G3844","is by",129,134],["G2281","the sea",135,142],["G5491","shore",143,148],["G0382","innumerable",149,160]]},"11:13":{"text":"These all died in faith, not having received the promises, but having seen them afar off, and were persuaded of them, and embraced them, and confessed that they were strangers and pilgrims on the earth.","words":[["G3778","These",0,5],["G3956","all",6,9],["G0599","died",10,14],["G2596","in",15,17],["G4102","faith",18,23],["G3361","not",25,28],["G2983","having received",29,44],["G1860","the promises",45,57],["G0235","but",59,62],["G1492","having seen",63,74],["G0846","them",75,79],["G4207","afar off",80,88],["G2532","and",90,93],["G3982","were persuaded of",94,111],["G2532","them, and",112,121],["G0782","embraced",122,130],["G2532","them, and",131,140],["G3670","confessed",141,150],["G3754","that",151,155],["G1526","they were",156,165],["G3581","strangers",166,175],["G2532","and",176,179],["G3927","pilgrims",180,188],["G1909","on",189,191],["G1093","the earth",192,201]]},"11:14":{"text":"For they that say such things declare plainly that they seek a country.","words":[["G1063","For",0,3],["G3004","they that say",4,17],["G5108","such things",18,29],["G1718","declare plainly",30,45],["G3754","that",46,50],["G1934","they seek",51,60],["G3968","a country",61,70]]},"11:15":{"text":"And truly, if they had been mindful of that country from whence they came out, they might have had opportunity to have returned.","words":[["G2532","And",0,3],["G3303","truly",4,9],["G1487","if",11,13],["G3421","they had been mindful",14,35],["G1565","of that",36,43],["G0575","country from",44,56],["G3739","whence",57,63],["G1831","they came out",64,77],["G0302","they might",79,89],["G2192","have had",90,98],["G2540","opportunity",99,110],["G0344","to have returned",111,127]]},"11:16":{"text":"But now they desire a better country, that is, an heavenly: wherefore God is not ashamed to be called their God: for he hath prepared for them a city.","words":[["G1161","But",0,3],["G3570","now",4,7],["G3713","they desire",8,19],["G2909","a better",20,28],["G5123","country, that is",29,45],["G2032","an heavenly",47,58],["G1352","wherefore",60,69],["G2316","God",70,73],["G1870","is",74,76],["G3756","not",77,80],["G1870","ashamed",81,88],["G0846","ashamed",81,88],["G1941","to be called",89,101],["G0846","their",102,107],["G2316","God",108,111],["G1063","for",113,116],["G2090","he hath prepared",117,133],["G0846","for them",134,142],["G4172","a city",143,149]]},"11:17":{"text":"By faith Abraham, when he was tried, offered up Isaac: and he that had received the promises offered up his only begotten son,","words":[["G4102","By faith",0,8],["G0011","Abraham",9,16],["G3985","when he was tried",18,35],["G4374","offered up",37,47],["G2464","Isaac",48,53],["G2532","and",55,58],["G0324","he that had received",59,79],["G1860","the promises",80,92],["G4374","offered up",93,103],["G3439","his only begotten",104,121]]},"11:18":{"text":"Of whom it was said, That in Isaac shall thy seed be called:","words":[["G4314","Of",0,2],["G3739","whom",3,7],["G2980","it was said",8,19],["G3754","That",21,25],["G1722","in",26,28],["G2464","Isaac",29,34],["G2564","shall",35,40],["G4671","thy",41,44],["G4690","seed",45,49],["G2564","be called",50,59]]},"11:19":{"text":"Accounting that God was able to raise him up, even from the dead; from whence also he received him in a figure.","words":[["G3049","Accounting",0,10],["G3754","that",11,15],["G2316","God",16,19],["G1415","was able",20,28],["G1453","to raise him up",29,44],["G2532","even",46,50],["G1537","from",51,55],["G3498","the dead",56,64],["G3606","from whence",66,77],["G2532","also",78,82],["G2865","he received",83,94],["G0846","him",95,98],["G1722","in",99,101],["G3850","a figure",102,110]]},"11:20":{"text":"By faith Isaac blessed Jacob and Esau concerning things to come.","words":[["G4102","By faith",0,8],["G2464","Isaac",9,14],["G2127","blessed",15,22],["G2384","Jacob",23,28],["G2532","and",29,32],["G2269","Esau",33,37],["G4012","concerning",38,48],["G3195","things to come",49,63]]},"11:21":{"text":"By faith Jacob, when he was a dying, blessed both the sons of Joseph; and worshipped, leaning upon the top of his staff.","words":[["G4102","By faith",0,8],["G2384","Jacob",9,14],["G0599","when he was a dying",16,35],["G2127","blessed",37,44],["G1538","both",45,49],["G5207","the sons",50,58],["G2501","of Joseph",59,68],["G2532","and",70,73],["G4352","worshipped",74,84],["G1909","leaning upon",86,98],["G0206","the top",99,106],["G0846","of his",107,113],["G4464","staff",114,119]]},"11:22":{"text":"By faith Joseph, when he died, made mention of the departing of the children of Israel; and gave commandment concerning his bones.","words":[["G4102","By faith",0,8],["G2501","Joseph",9,15],["G5053","when he died",17,29],["G3421","made mention",31,43],["G4012","of",44,46],["G1841","the departing",47,60],["G5207","of the children",61,76],["G2474","of Israel",77,86],["G2532","and",88,91],["G1781","gave commandment",92,108],["G4012","concerning",109,119],["G0846","his",120,123],["G3747","bones",124,129]]},"11:23":{"text":"By faith Moses, when he was born, was hid three months of his parents, because they saw he was a proper child; and they were not afraid of the king's commandment.","words":[["G4102","By faith",0,8],["G3475","Moses",9,14],["G1080","when he was born",16,32],["G2928","was hid",34,41],["G5150","three months",42,54],["G5259","of",55,57],["G0846","his",58,61],["G3962","parents",62,69],["G1360","because",71,78],["G1492","they saw",79,87],["G0791","he was a proper",88,103],["G3813","child",104,109],["G2532","and",111,114],["G5399","they were",115,124],["G3756","not",125,128],["G5399","afraid",129,135],["G0935","of the king's",136,149],["G1297","commandment",150,161]]},"11:24":{"text":"By faith Moses, when he was come to years, refused to be called the son of Pharaoh's daughter;","words":[["G4102","By faith",0,8],["G3475","Moses",9,14],["G1096","when he was come",16,32],["G3173","to years",33,41],["G0720","refused",43,50],["G3004","to be called",51,63],["G5207","the son",64,71],["G5328","of Pharaoh's",72,84],["G2364","daughter",85,93]]},"11:25":{"text":"Choosing rather to suffer affliction with the people of God, than to enjoy the pleasures of sin for a season;","words":[["G0138","Choosing",0,8],["G3123","rather",9,15],["G4778","to suffer affliction",16,36],["G2992","with the people",37,52],["G2316","of God",53,59],["G2228","than",61,65],["G2192","to enjoy the pleasures",66,88],["G0619","to enjoy the pleasures",66,88],["G0266","of sin",89,95],["G4340","for a season",96,108]]},"11:26":{"text":"Esteeming the reproach of Christ greater riches than the treasures in Egypt: for he had respect unto the recompence of the reward.","words":[["G2233","Esteeming",0,9],["G3680","the reproach",10,22],["G5547","of Christ",23,32],["G3187","greater",33,40],["G4149","riches",41,47],["G2233","than",48,52],["G2344","the treasures",53,66],["G1722","in",67,69],["G0125","Egypt",70,75],["G1063","for",77,80],["G0578","he had respect",81,95],["G1519","unto",96,100],["G3405","the recompence of the reward",101,129]]},"11:27":{"text":"By faith he forsook Egypt, not fearing the wrath of the king: for he endured, as seeing him who is invisible.","words":[["G4102","By faith",0,8],["G2641","he forsook",9,19],["G0125","Egypt",20,25],["G3361","not",27,30],["G5399","fearing",31,38],["G2372","the wrath",39,48],["G0935","of the king",49,60],["G1063","for",62,65],["G2594","he endured",66,76],["G5613","as",78,80],["G3708","seeing",81,87],["G0517","him who is invisible",88,108]]},"11:28":{"text":"Through faith he kept the passover, and the sprinkling of blood, lest he that destroyed the firstborn should touch them.","words":[["G4102","Through faith",0,13],["G4160","he kept",14,21],["G3957","the passover",22,34],["G2532","and",36,39],["G4378","the sprinkling",40,54],["G0129","of blood",55,63],["G3363","lest",65,69],["G3645","he that destroyed",70,87],["G4416","the firstborn",88,101],["G2345","should touch",102,114],["G0846","them",115,119]]},"11:29":{"text":"By faith they passed through the Red sea as by dry land: which the Egyptians assaying to do were drowned.","words":[["G4102","By faith",0,8],["G1224","they passed through",9,28],["G2063","the Red",29,36],["G2281","sea",37,40],["G5613","as",41,43],["G1223","by",44,46],["G3584","dry",47,50],["G3739","land: which",51,62],["G0124","the Egyptians",63,76],["G3984","assaying",77,85],["G2983","to do",86,91],["G2666","were drowned",92,104]]},"11:30":{"text":"By faith the walls of Jericho fell down, after they were compassed about seven days.","words":[["G4102","By faith",0,8],["G5038","the walls",9,18],["G2410","of Jericho",19,29],["G4098","fell down",30,39],["G2944","after they were compassed",41,66],["G1909","about",67,72],["G2033","seven",73,78],["G2250","days",79,83]]},"11:31":{"text":"By faith the harlot Rahab perished not with them that believed not, when she had received the spies with peace.","words":[["G4102","By faith",0,8],["G4204","the harlot",9,19],["G4460","Rahab",20,25],["G4881","perished",26,34],["G3756","not",35,38],["G0544","with them that believed not",39,66],["G1209","when she had received",68,89],["G2685","the spies",90,99],["G3326","with",100,104],["G1515","peace",105,110]]},"11:32":{"text":"And what shall I more say? for the time would fail me to tell of Gedeon, and of Barak, and of Samson, and of Jephthae; of David also, and Samuel, and of the prophets:","words":[["G2532","And",0,3],["G5101","what",4,8],["G3004","shall I",9,16],["G2089","more",17,21],["G3004","say",22,25],["G1063","for",27,30],["G5550","the time",31,39],["G1952","would fail",40,50],["G3165","me",51,53],["G1334","to tell",54,61],["G4012","of",62,64],["G1066","Gedeon",65,71],["G5037","and",73,76],["G0913","of Barak",77,85],["G2532","and",87,90],["G4546","of Samson",91,100],["G2532","and",102,105],["G2422","of Jephthae",106,117],["G1138","of David",119,127],["G2532","also",128,132],["G5037","and",134,137],["G4545","Samuel",138,144],["G2532","and",146,149],["G4396","of the prophets",150,165]]},"11:33":{"text":"Who through faith subdued kingdoms, wrought righteousness, obtained promises, stopped the mouths of lions,","words":[["G3739","Who",0,3],["G1223","through",4,11],["G4102","faith",12,17],["G2610","subdued",18,25],["G0932","kingdoms",26,34],["G2038","wrought",36,43],["G1343","righteousness",44,57],["G2013","obtained",59,67],["G1860","promises",68,76],["G5420","stopped",78,85],["G4750","the mouths",86,96],["G3023","of lions",97,105]]},"11:34":{"text":"Quenched the violence of fire, escaped the edge of the sword, out of weakness were made strong, waxed valiant in fight, turned to flight the armies of the aliens.","words":[["G4570","Quenched",0,8],["G1411","the violence",9,21],["G4442","of fire",22,29],["G5343","escaped",31,38],["G4750","the edge",39,47],["G3162","of the sword",48,60],["G0575","out of",62,68],["G0769","weakness",69,77],["G1743","were made strong",78,94],["G1096","waxed",96,101],["G2478","valiant",102,109],["G1722","in",110,112],["G4171","fight",113,118],["G2827","turned to flight",120,136],["G3925","the armies",137,147],["G0245","of the aliens",148,161]]},"11:35":{"text":"Women received their dead raised to life again: and others were tortured, not accepting deliverance; that they might obtain a better resurrection:","words":[["G1135","Women",0,5],["G2983","received",6,14],["G0846","their",15,20],["G3498","dead",21,25],["G1537","raised to life again",26,46],["G0386","raised to life again",26,46],["G1161","and",48,51],["G0243","others",52,58],["G5178","were tortured",59,72],["G3756","not",74,77],["G4327","accepting",78,87],["G0629","deliverance",88,99],["G2443","that",101,105],["G5177","they might obtain",106,123],["G2909","a better",124,132],["G0386","resurrection",133,145]]},"11:36":{"text":"And others had trial of cruel mockings and scourgings, yea, moreover of bonds and imprisonment:","words":[["G1161","And",0,3],["G2087","others",4,10],["G2983","had",11,14],["G3984","trial",15,20],["G1701","of cruel mockings",21,38],["G2532","and",39,42],["G3148","scourgings",43,53],["G1161","yea",55,58],["G2089","moreover",60,68],["G1199","of bonds",69,77],["G2532","and",78,81],["G5438","imprisonment",82,94]]},"11:37":{"text":"They were stoned, they were sawn asunder, were tempted, were slain with the sword: they wandered about in sheepskins and goatskins; being destitute, afflicted, tormented;","words":[["G3034","They were stoned",0,16],["G4249","they were sawn asunder",18,40],["G3985","were tempted",42,54],["G0599","were slain",56,66],["G1722","with",67,71],["G5408","the sword",72,81],["G3162","the sword",72,81],["G4022","they wandered about",83,102],["G1722","in",103,105],["G3374","sheepskins",106,116],["G1722","and",117,120],["G0122","goatskins",121,130],["G1192","goatskins",121,130],["G5302","being destitute",132,147],["G2346","afflicted",149,158],["G2558","tormented",160,169]]},"11:38":{"text":"(Of whom the world was not worthy:) they wandered in deserts, and in mountains, and in dens and caves of the earth.","words":[["G3739","(Of whom",0,8],["G2889","the world",9,18],["G2258","was",19,22],["G3756","not",23,26],["G0514","worthy",27,33],["G4105",") they wandered",34,49],["G1722","in",50,52],["G2047","deserts",53,60],["G2532","and",62,65],["G3735","in mountains",66,78],["G2532","and",80,83],["G4693","in dens",84,91],["G2532","and",92,95],["G3692","caves",96,101],["G1093","of the earth",102,114]]},"11:39":{"text":"And these all, having obtained a good report through faith, received not the promise:","words":[["G2532","And",0,3],["G3778","these",4,9],["G3956","all",10,13],["G3140","having obtained a good report",15,44],["G1223","through",45,52],["G4102","faith",53,58],["G2865","received",60,68],["G3756","not",69,72],["G1860","the promise",73,84]]},"11:40":{"text":"God having provided some better thing for us, that they without us should not be made perfect.","words":[["G2316","God",0,3],["G4265","having provided",4,19],["G5100","some",20,24],["G2909","better",25,31],["G5100","thing",32,37],["G4012","for",38,41],["G2257","us",42,44],["G3363","that",46,50],["G5048","they",51,55],["G5565","without",56,63],["G2257","us",64,66],["G5048","should",67,73],["G3363","not",74,77],["G5048","be made perfect",78,93]]},"12:1":{"text":"Wherefore seeing we also are compassed about with so great a cloud of witnesses, let us lay aside every weight, and the sin which doth so easily beset us, and let us run with patience the race that is set before us,","words":[["G5105","Wherefore",0,9],["G2532","seeing we also",10,24],["G2192","are",25,28],["G4029","compassed about",29,44],["G2254","compassed about",29,44],["G5118","with so great",45,58],["G3509","a cloud",59,66],["G3144","of witnesses",67,79],["G0659","let",81,84],["G2249","us",85,87],["G0659","lay aside",88,97],["G3956","every",98,103],["G3591","weight",104,110],["G2532","and",112,115],["G0266","the sin",116,123],["G2139","which doth so easily beset",124,150],["G5143","us, and let us run",151,169],["G1223","with",170,174],["G5281","patience",175,183],["G0073","the race",184,192],["G4295","that is set before",193,211],["G2254","us",212,214]]},"12:2":{"text":"Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God.","words":[["G0872","Looking",0,7],["G1519","unto",8,12],["G2424","Jesus",13,18],["G0747","the author",19,29],["G2532","and",30,33],["G5051","finisher",34,42],["G4102","of our faith",43,55],["G3739","who",57,60],["G0473","for",61,64],["G5479","the joy",65,72],["G4295","that was set before",73,92],["G0846","him",93,96],["G5278","endured",97,104],["G4716","the cross",105,114],["G2706","despising",116,125],["G0152","the shame",126,135],["G5037","and",137,140],["G2523","is set down",141,152],["G1722","at",153,155],["G1188","the right hand",156,170],["G2362","of the throne",171,184],["G2316","of God",185,191]]},"12:3":{"text":"For consider him that endured such contradiction of sinners against himself, lest ye be wearied and faint in your minds.","words":[["G1063","For",0,3],["G0357","consider",4,12],["G5278","him that endured",13,29],["G5108","such",30,34],["G0485","contradiction",35,48],["G5259","of",49,51],["G0268","sinners",52,59],["G1519","against",60,67],["G0846","himself",68,75],["G3363","lest",77,81],["G2577","ye be wearied",82,95],["G1590","and faint",96,105],["G5216","in your",106,113],["G5590","minds",114,119]]},"12:4":{"text":"Ye have not yet resisted unto blood, striving against sin.","words":[["G0478","Ye have",0,7],["G3768","not yet",8,15],["G0478","resisted",16,24],["G3360","unto",25,29],["G0129","blood",30,35],["G0464","striving",37,45],["G4314","against",46,53],["G0266","sin",54,57]]},"12:5":{"text":"And ye have forgotten the exhortation which speaketh unto you as unto children, My son, despise not thou the chastening of the Lord, nor faint when thou art rebuked of him:","words":[["G2532","And",0,3],["G1585","ye have forgotten",4,21],["G3874","the exhortation",22,37],["G3748","which",38,43],["G1256","speaketh",44,52],["G5213","unto you",53,61],["G5613","as",62,64],["G5207","unto children",65,78],["G3450","My",80,82],["G5207","son",83,86],["G3643","despise",88,95],["G3361","not",96,99],["G3643","thou",100,104],["G3809","the chastening",105,119],["G2962","of the Lord",120,131],["G3366","nor",133,136],["G1590","faint",137,142],["G1651","when thou art rebuked",143,164],["G5259","of",165,167],["G0846","him",168,171]]},"12:6":{"text":"For whom the Lord loveth he chasteneth, and scourgeth every son whom he receiveth.","words":[["G1063","For",0,3],["G3739","whom",4,8],["G2962","the Lord",9,17],["G0025","loveth",18,24],["G3811","he chasteneth",25,38],["G1161","and",40,43],["G3146","scourgeth",44,53],["G3956","every",54,59],["G5207","son",60,63],["G3739","whom",64,68],["G3858","he receiveth",69,81]]},"12:7":{"text":"If ye endure chastening, God dealeth with you as with sons; for what son is he whom the father chasteneth not?","words":[["G1487","If",0,2],["G5278","ye endure",3,12],["G3809","chastening",13,23],["G2316","God",25,28],["G4374","dealeth",29,36],["G5213","with you",37,45],["G5613","as",46,48],["G5207","with sons",49,58],["G1063","for",60,63],["G5101","what",64,68],["G5207","son",69,72],["G2076","is he",73,78],["G3739","whom",79,83],["G3962","the father",84,94],["G3811","chasteneth",95,105],["G3756","not",106,109]]},"12:8":{"text":"But if ye be without chastisement, whereof all are partakers, then are ye bastards, and not sons.","words":[["G1161","But",0,3],["G1487","if",4,6],["G2075","ye be",7,12],["G5565","without",13,20],["G3809","chastisement",21,33],["G3739","whereof",35,42],["G3956","all",43,46],["G1096","are",47,50],["G3353","partakers",51,60],["G0686","then",62,66],["G2075","are ye",67,73],["G3541","bastards",74,82],["G2532","and",84,87],["G3756","not",88,91],["G5207","sons",92,96]]},"12:9":{"text":"Furthermore we have had fathers of our flesh which corrected us, and we gave them reverence: shall we not much rather be in subjection unto the Father of spirits, and live?","words":[["G1534","Furthermore",0,11],["G3303","Furthermore",0,11],["G2192","we have had",12,23],["G3962","fathers",24,31],["G2257","of our",32,38],["G4561","flesh",39,44],["G3810","which corrected",45,60],["G2532","us, and",61,68],["G1788","we gave them reverence",69,91],["G5293","shall we",93,101],["G3756","not",102,105],["G4183","much",106,110],["G3123","rather",111,117],["G5293","be in subjection",118,134],["G3962","unto the Father",135,150],["G4151","of spirits",151,161],["G2532","and",163,166],["G2198","live",167,171]]},"12:10":{"text":"For they verily for a few days chastened us after their own pleasure; but he for our profit, that we might be partakers of his holiness.","words":[["G1063","For",0,3],["G3303","they verily",4,15],["G4314","for",16,19],["G3641","a few",20,25],["G2250","days",26,30],["G3811","chastened",31,40],["G2596","us after",41,49],["G0846","their own",50,59],["G1380","pleasure",60,68],["G1161","but",70,73],["G1909","he for",74,80],["G4851","our profit",81,91],["G1519","that",93,97],["G3335","we might be partakers",98,119],["G0846","of his",120,126],["G0041","holiness",127,135]]},"12:11":{"text":"Now no chastening for the present seemeth to be joyous, but grievous: nevertheless afterward it yieldeth the peaceable fruit of righteousness unto them which are exercised thereby.","words":[["G1161","Now",0,3],["G3956","no",4,6],["G3756","no",4,6],["G3809","chastening",7,17],["G4314","for",18,21],["G3303","for",18,21],["G3918","the present",22,33],["G1380","seemeth",34,41],["G1511","to be",42,47],["G5479","joyous",48,54],["G0235","but",56,59],["G3077","grievous",60,68],["G1161","nevertheless",70,82],["G5305","afterward",83,92],["G0591","it yieldeth",93,104],["G1516","the peaceable",105,118],["G2590","fruit",119,124],["G1343","of righteousness",125,141],["G1128","unto them which are exercised",142,171],["G1223","thereby",172,179],["G0846","thereby",172,179]]},"12:12":{"text":"Wherefore lift up the hands which hang down, and the feeble knees;","words":[["G1352","Wherefore",0,9],["G0461","lift up",10,17],["G5495","the hands",18,27],["G3935","which hang down",28,43],["G2532","and",45,48],["G3886","the feeble",49,59],["G1119","knees",60,65]]},"12:13":{"text":"And make straight paths for your feet, lest that which is lame be turned out of the way; but let it rather be healed.","words":[["G2532","And",0,3],["G4160","make",4,8],["G3717","straight",9,17],["G5163","paths",18,23],["G5216","for your",24,32],["G4228","feet",33,37],["G3363","lest that",39,48],["G5560","which is lame",49,62],["G1624","be turned out of the way",63,87],["G1161","but",89,92],["G2390","let it",93,99],["G3123","rather",100,106],["G2390","be healed",107,116]]},"12:14":{"text":"Follow peace with all men, and holiness, without which no man shall see the Lord:","words":[["G1377","Follow",0,6],["G1515","peace",7,12],["G3326","with",13,17],["G3956","all",18,21],["G2532","men, and",22,30],["G0038","holiness",31,39],["G5565","without",41,48],["G3739","which",49,54],["G3762","no man",55,61],["G3700","shall see",62,71],["G2962","the Lord",72,80]]},"12:15":{"text":"Looking diligently lest any man fail of the grace of God; lest any root of bitterness springing up trouble you, and thereby many be defiled;","words":[["G1983","Looking diligently",0,18],["G3361","lest",19,23],["G5100","any man",24,31],["G5302","fail",32,36],["G0575","of",37,39],["G5485","the grace",40,49],["G2316","of God",50,56],["G3361","lest",58,62],["G5100","any",63,66],["G4491","root",67,71],["G4088","of bitterness",72,85],["G5453","springing",86,95],["G0507","up",96,98],["G1776","trouble",99,106],["G2532","you, and",107,115],["G1223","thereby",116,123],["G5026","thereby",116,123],["G4183","many",124,128],["G3392","be defiled",129,139]]},"12:16":{"text":"Lest there be any fornicator, or profane person, as Esau, who for one morsel of meat sold his birthright.","words":[["G3361","Lest",0,4],["G5100","there be any",5,17],["G4205","fornicator",18,28],["G2228","or",30,32],["G0952","profane person",33,47],["G5613","as",49,51],["G2269","Esau",52,56],["G3739","who",58,61],["G0473","for",62,65],["G3391","one",66,69],["G1035","morsel of meat",70,84],["G0591","sold",85,89],["G0846","his",90,93],["G4415","birthright",94,104]]},"12:17":{"text":"For ye know how that afterward, when he would have inherited the blessing, he was rejected: for he found no place of repentance, though he sought it carefully with tears.","words":[["G1063","For",0,3],["G2467","ye know",4,11],["G3754","how",12,15],["G2532","that afterward",16,30],["G3347","that afterward",16,30],["G2309","when he would",32,45],["G2816","have inherited",46,60],["G2129","the blessing",61,73],["G0593","he was rejected",75,90],["G1063","for",92,95],["G2147","he found",96,104],["G3756","no",105,107],["G5117","place",108,113],["G3341","of repentance",114,127],["G2539","though",129,135],["G1567","he sought",136,145],["G0846","it",146,148],["G1567","carefully",149,158],["G3326","with",159,163],["G1144","tears",164,169]]},"12:18":{"text":"For ye are not come unto the mount that might be touched, and that burned with fire, nor unto blackness, and darkness, and tempest,","words":[["G1063","For",0,3],["G4334","ye are",4,10],["G3756","not",11,14],["G4334","come",15,19],["G3735","unto the mount",20,34],["G5584","that might be touched",35,56],["G2532","and",58,61],["G2545","that burned",62,73],["G4442","with fire",74,83],["G2532","nor",85,88],["G1105","unto blackness",89,103],["G2532","and",105,108],["G4655","darkness",109,117],["G2532","and",119,122],["G2366","tempest",123,130]]},"12:19":{"text":"And the sound of a trumpet, and the voice of words; which voice they that heard intreated that the word should not be spoken to them any more:","words":[["G2532","And",0,3],["G2279","the sound",4,13],["G4536","of a trumpet",14,26],["G2532","and",28,31],["G5456","the voice",32,41],["G4487","of words",42,50],["G3739","which",52,57],["G0191","voice they that heard",58,79],["G3868","intreated",80,89],["G3056","that the word",90,103],["G4369","should",104,110],["G3361","not",111,114],["G4369","be spoken",115,124],["G0846","to them",125,132],["G3361","any more",133,141]]},"12:20":{"text":"(For they could not endure that which was commanded, And if so much as a beast touch the mountain, it shall be stoned, or thrust through with a dart:","words":[["G1063","(For",0,4],["G5342","they could",5,15],["G3756","not",16,19],["G5342","endure",20,26],["G1291","that which was commanded",27,51],["G2579","And if so much as",53,70],["G2342","a beast",71,78],["G2345","touch",79,84],["G3735","the mountain",85,97],["G3036","it shall be stoned",99,117],["G2228","or",119,121],["G2700","thrust through",122,136],["G1002","with a dart",137,148]]},"12:21":{"text":"And so terrible was the sight, that Moses said, I exceedingly fear and quake:)","words":[["G2532","And",0,3],["G3779","so",4,6],["G5398","terrible",7,15],["G2258","was",16,19],["G5324","the sight",20,29],["G3475","that Moses",31,41],["G2036","said",42,46],["G1630","I exceedingly fear",48,66],["G1510","I exceedingly fear",48,66],["G2532","and",67,70],["G1790","quake",71,76]]},"12:22":{"text":"But ye are come unto mount Sion, and unto the city of the living God, the heavenly Jerusalem, and to an innumerable company of angels,","words":[["G0235","But",0,3],["G4334","ye are come",4,15],["G3735","unto mount",16,26],["G4622","Sion",27,31],["G2532","and",33,36],["G4172","unto the city",37,50],["G2198","of the living",51,64],["G2316","God",65,68],["G2032","the heavenly",70,82],["G2419","Jerusalem",83,92],["G2532","and",94,97],["G3461","to an innumerable company",98,123],["G0032","of angels",124,133]]},"12:23":{"text":"To the general assembly and church of the firstborn, which are written in heaven, and to God the Judge of all, and to the spirits of just men made perfect,","words":[["G3831","To the general assembly",0,23],["G2532","and",24,27],["G1577","church",28,34],["G4416","of the firstborn",35,51],["G0583","which are written",53,70],["G1722","in",71,73],["G3772","heaven",74,80],["G2532","and",82,85],["G2316","to God",86,92],["G2923","the Judge",93,102],["G3956","of all",103,109],["G2532","and",111,114],["G4151","to the spirits",115,129],["G1342","of just men",130,141],["G5048","made perfect",142,154]]},"12:24":{"text":"And to Jesus the mediator of the new covenant, and to the blood of sprinkling, that speaketh better things than that of Abel.","words":[["G2532","And",0,3],["G2424","to Jesus",4,12],["G3316","the mediator",13,25],["G3501","of the new",26,36],["G1242","covenant",37,45],["G2532","and",47,50],["G0129","to the blood",51,63],["G4473","of sprinkling",64,77],["G2980","that speaketh",79,92],["G2909","better things",93,106],["G3844","than",107,111],["G0006","that of Abel",112,124]]},"12:25":{"text":"See that ye refuse not him that speaketh. For if they escaped not who refused him that spake on earth, much more shall not we escape, if we turn away from him that speaketh from heaven:","words":[["G0991","See",0,3],["G3868","that ye refuse",4,18],["G3361","not",19,22],["G2980","him that speaketh",23,40],["G1063","For",42,45],["G1487","if",46,48],["G1565","they",49,53],["G5343","escaped",54,61],["G3756","not",62,65],["G3868","who refused him",66,81],["G5537","that spake",82,92],["G1909","on",93,95],["G1093","earth",96,101],["G4183","much",103,107],["G3123","more",108,112],["G2249","shall not we",113,125],["G0654","escape, if we turn away from him",126,158],["G0575","that speaketh from",159,177],["G3772","heaven",178,184]]},"12:26":{"text":"Whose voice then shook the earth: but now he hath promised, saying, Yet once more I shake not the earth only, but also heaven.","words":[["G3739","Whose",0,5],["G5456","voice",6,11],["G5119","then",12,16],["G4531","shook",17,22],["G1093","the earth",23,32],["G1161","but",34,37],["G3568","now",38,41],["G1861","he hath promised",42,58],["G3004","saying",60,66],["G2089","Yet",68,71],["G0530","once more",72,81],["G1473","I",82,83],["G4579","shake",84,89],["G3756","not",90,93],["G1093","the earth",94,103],["G3440","only",104,108],["G0235","but",110,113],["G2532","also",114,118],["G3772","heaven",119,125]]},"12:27":{"text":"And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain.","words":[["G1161","And",0,3],["G2089","this word, Yet",4,18],["G0530","once more",19,28],["G1213","signifieth",30,40],["G3331","the removing",41,53],["G4531","of those things that are shaken",54,85],["G5613","as",87,89],["G4160","of things that are made",90,113],["G2443","that",115,119],["G3361","those things which cannot",120,145],["G4531","be shaken",146,155],["G3306","may remain",156,166]]},"12:28":{"text":"Wherefore we receiving a kingdom which cannot be moved, let us have grace, whereby we may serve God acceptably with reverence and godly fear:","words":[["G1352","Wherefore",0,9],["G3880","we receiving",10,22],["G0932","a kingdom",23,32],["G0761","which cannot be moved",33,54],["G2192","let us have",56,67],["G5485","grace",68,73],["G1223","whereby",75,82],["G3739","whereby",75,82],["G3000","we may serve",83,95],["G2316","God",96,99],["G2102","acceptably",100,110],["G3326","with",111,115],["G0127","reverence",116,125],["G2532","and",126,129],["G2124","godly fear",130,140]]},"12:29":{"text":"For our God is a consuming fire.","words":[["G2532","For",0,3],["G1063","For",0,3],["G2257","our",4,7],["G2316","God",8,11],["G2654","is a consuming",12,26],["G4442","fire",27,31]]},"13:1":{"text":"Let brotherly love continue.","words":[["G3306","Let",0,3],["G5360","brotherly love",4,18],["G3306","continue",19,27]]},"13:2":{"text":"Be not forgetful to entertain strangers: for thereby some have entertained angels unawares.","words":[["G1950","Be",0,2],["G3361","not",3,6],["G1950","forgetful",7,16],["G5381","to entertain strangers",17,39],["G1063","for",41,44],["G1223","thereby",45,52],["G5026","thereby",45,52],["G5100","some",53,57],["G3579","have entertained",58,74],["G0032","angels",75,81],["G2990","unawares",82,90]]},"13:3":{"text":"Remember them that are in bonds, as bound with them; and them which suffer adversity, as being yourselves also in the body.","words":[["G3403","Remember",0,8],["G1198","them that are in bonds",9,31],["G5613","as",33,35],["G4887","bound with them",36,51],["G2558","and them which suffer adversity",53,84],["G5613","as",86,88],["G5607","being",89,94],["G0846","yourselves",95,105],["G2532","also",106,110],["G1722","in",111,113],["G4983","the body",114,122]]},"13:4":{"text":"Marriage is honourable in all, and the bed undefiled: but whoremongers and adulterers God will judge.","words":[["G1062","Marriage",0,8],["G5093","is honourable",9,22],["G1722","in",23,25],["G3956","all",26,29],["G2532","and",31,34],["G2845","the bed",35,42],["G0283","undefiled",43,52],["G1161","but",54,57],["G4205","whoremongers",58,70],["G2532","and",71,74],["G3432","adulterers",75,85],["G2316","God",86,89],["G2919","will judge",90,100]]},"13:5":{"text":"Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee.","words":[["G5158","Let your conversation",0,21],["G0866","be without covetousness",22,45],["G0714","and be content",47,61],["G3918","with such things as ye have",62,89],["G1063","for",91,94],["G0846","he",95,97],["G2046","hath said",98,107],["G3364","I will never",109,121],["G0447","leave",122,127],["G4571","thee",128,132],["G3761","nor",134,137],["G3364","nor",134,137],["G1459","forsake",138,145],["G4571","thee",146,150]]},"13:6":{"text":"So that we may boldly say, The Lord is my helper, and I will not fear what man shall do unto me.","words":[["G5620","So that",0,7],["G2248","we",8,10],["G2292","may boldly",11,21],["G3004","say",22,25],["G2962","The Lord",27,35],["G1698","is my",36,41],["G0998","helper",42,48],["G2532","and",50,53],["G5399","I will",54,60],["G3756","not",61,64],["G5399","fear",65,69],["G5101","what",70,74],["G0444","man",75,78],["G4160","shall do",79,87],["G3427","unto me",88,95]]},"13:7":{"text":"Remember them which have the rule over you, who have spoken unto you the word of God: whose faith follow, considering the end of their conversation.","words":[["G3421","Remember",0,8],["G2233","them which have the rule",9,33],["G5216","over you",34,42],["G3748","who",44,47],["G2980","have spoken",48,59],["G5213","unto you",60,68],["G3056","the word",69,77],["G2316","of God",78,84],["G3739","whose",86,91],["G4102","faith",92,97],["G3401","follow",98,104],["G0333","considering",106,117],["G1545","the end",118,125],["G0391","of their conversation",126,147]]},"13:8":{"text":"Jesus Christ the same yesterday, and to day, and for ever.","words":[["G2424","Jesus",0,5],["G5547","Christ",6,12],["G0846","the same",13,21],["G5504","yesterday",22,31],["G2532","and",33,36],["G4594","to day",37,43],["G2532","and",45,48],["G1519","for",49,52],["G0165","ever",53,57]]},"13:9":{"text":"Be not carried about with divers and strange doctrines. For it is a good thing that the heart be established with grace; not with meats, which have not profited them that have been occupied therein.","words":[["G4064","Be",0,2],["G3361","not",3,6],["G4064","carried about",7,20],["G4164","with divers",21,32],["G2532","and",33,36],["G3581","strange",37,44],["G1322","doctrines",45,54],["G1063","For",56,59],["G2570","it is a good thing",60,78],["G2588","that the heart",79,93],["G0950","be established",94,108],["G5485","with grace",109,119],["G3756","not",121,124],["G1033","with meats",125,135],["G5623","which have",137,147],["G3756","not",148,151],["G5623","profited",152,160],["G4043","them that have been occupied",161,189],["G1722","therein",190,197],["G3739","therein",190,197]]},"13:10":{"text":"We have an altar, whereof they have no right to eat which serve the tabernacle.","words":[["G2192","We have",0,7],["G2379","an altar",8,16],["G1537","whereof",18,25],["G3739","whereof",18,25],["G2192","they have",26,35],["G3756","no",36,38],["G1849","right",39,44],["G5315","to eat",45,51],["G3000","which serve",52,63],["G4633","the tabernacle",64,78]]},"13:11":{"text":"For the bodies of those beasts, whose blood is brought into the sanctuary by the high priest for sin, are burned without the camp.","words":[["G1063","For",0,3],["G4983","the bodies",4,14],["G5130","of those",15,23],["G2226","beasts",24,30],["G3739","whose",32,37],["G0129","blood",38,43],["G1533","is brought",44,54],["G1519","into",55,59],["G0039","the sanctuary",60,73],["G1223","by",74,76],["G0749","the high priest",77,92],["G4012","for",93,96],["G0266","sin",97,100],["G2618","are burned",102,112],["G1854","without",113,120],["G3925","the camp",121,129]]},"13:12":{"text":"Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate.","words":[["G1352","Wherefore",0,9],["G2424","Jesus",10,15],["G2532","also",16,20],["G2443","that",22,26],["G0037","he might sanctify",27,44],["G2992","the people",45,55],["G1223","with",56,60],["G2398","his own",61,68],["G0129","blood",69,74],["G3958","suffered",76,84],["G1854","without",85,92],["G4439","the gate",93,101]]},"13:13":{"text":"Let us go forth therefore unto him without the camp, bearing his reproach.","words":[["G1831","Let us go forth",0,15],["G5106","therefore",16,25],["G4314","unto",26,30],["G0846","him",31,34],["G1854","without",35,42],["G3925","the camp",43,51],["G5342","bearing",53,60],["G0846","his",61,64],["G3680","reproach",65,73]]},"13:14":{"text":"For here have we no continuing city, but we seek one to come.","words":[["G1063","For",0,3],["G5602","here",4,8],["G2192","have we",9,16],["G3756","no",17,19],["G3306","continuing",20,30],["G4172","city",31,35],["G0235","but",37,40],["G1934","we seek one",41,52],["G3195","to come",53,60]]},"13:15":{"text":"By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name.","words":[["G1223","By",0,2],["G0846","him",3,6],["G3767","therefore",7,16],["G0399","let us offer",17,29],["G2378","the sacrifice",30,43],["G0133","of praise",44,53],["G2316","to God",54,60],["G1275","continually",61,72],["G5123","that is",74,81],["G2590","the fruit",83,92],["G5491","of our lips",93,104],["G3670","giving thanks",105,118],["G0846","to his",119,125],["G3686","name",126,130]]},"13:16":{"text":"But to do good and to communicate forget not: for with such sacrifices God is well pleased.","words":[["G1161","But",0,3],["G2140","to do good",4,14],["G2532","and",15,18],["G2842","to communicate",19,33],["G1950","forget",34,40],["G3361","not",41,44],["G1063","for",46,49],["G5108","with such",50,59],["G2378","sacrifices",60,70],["G2316","God",71,74],["G2100","is well pleased",75,90]]},"13:17":{"text":"Obey them that have the rule over you, and submit yourselves: for they watch for your souls, as they that must give account, that they may do it with joy, and not with grief: for that is unprofitable for you.","words":[["G3982","Obey",0,4],["G2233","them that have the rule",5,28],["G5216","over you",29,37],["G2532","and",39,42],["G5226","submit yourselves",43,60],["G1063","for",62,65],["G0846","they",66,70],["G0069","watch",71,76],["G5228","for",77,80],["G5216","your",81,85],["G5590","souls",86,91],["G5613","as",93,95],["G0591","they that must give",96,115],["G3056","account",116,123],["G2443","that",125,129],["G4160","they may do",130,141],["G5124","it",142,144],["G3326","with",145,149],["G5479","joy",150,153],["G2532","and",155,158],["G3361","not",159,162],["G4727","with grief",163,173],["G1063","for",175,178],["G5124","that",179,183],["G0255","is unprofitable",184,199],["G5213","for you",200,207]]},"13:18":{"text":"Pray for us: for we trust we have a good conscience, in all things willing to live honestly.","words":[["G4336","Pray",0,4],["G4012","for",5,8],["G2257","us",9,11],["G1063","for",13,16],["G3754","for",13,16],["G3982","we trust",17,25],["G2192","we have",26,33],["G2570","a good",34,40],["G4893","conscience",41,51],["G1722","in",53,55],["G3956","all things",56,66],["G2309","willing",67,74],["G0390","to live",75,82],["G2573","honestly",83,91]]},"13:19":{"text":"But I beseech you the rather to do this, that I may be restored to you the sooner.","words":[["G1161","But",0,3],["G3870","I beseech",4,13],["G4056","you the rather",14,28],["G4160","to do",29,34],["G5124","this",35,39],["G2443","that",41,45],["G0600","I may be restored",46,63],["G5213","to you",64,70],["G5032","the sooner",71,81]]},"13:20":{"text":"Now the God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant,","words":[["G1161","Now",0,3],["G2316","the God",4,11],["G1515","of peace",12,20],["G0321","that brought again",22,40],["G1537","from",41,45],["G3498","the dead",46,54],["G2257","our",55,58],["G2962","Lord",59,63],["G2424","Jesus",64,69],["G3173","that great",71,81],["G4166","shepherd",82,90],["G4263","of the sheep",91,103],["G1722","through",105,112],["G0129","the blood",113,122],["G0166","of the everlasting",123,141],["G1242","covenant",142,150]]},"13:21":{"text":"Make you perfect in every good work to do his will, working in you that which is wellpleasing in his sight, through Jesus Christ; to whom be glory for ever and ever. Amen.","words":[["G2675","Make",0,4],["G5209","you",5,8],["G2675","perfect",9,16],["G1722","in",17,19],["G3956","every",20,25],["G0018","good",26,30],["G2041","work",31,35],["G1519","to",36,38],["G4160","do",39,41],["G0846","his",42,45],["G2307","will",46,50],["G4160","working",52,59],["G1722","in",60,62],["G5213","you",63,66],["G2101","that which is wellpleasing",67,93],["G0846","in his",94,100],["G1799","sight",101,106],["G1223","through",108,115],["G2424","Jesus",116,121],["G5547","Christ",122,128],["G3739","to whom",130,137],["G1391","be glory",138,146],["G1519","for",147,150],["G0165","ever",151,155],["G0165","and ever",156,164],["G0281","Amen",166,170]]},"13:22":{"text":"And I beseech you, brethren, suffer the word of exhortation: for I have written a letter unto you in few words.","words":[["G1161","And",0,3],["G3870","I beseech",4,13],["G5209","you",14,17],["G0080","brethren",19,27],["G0430","suffer",29,35],["G3056","the word",36,44],["G3874","of exhortation",45,59],["G1063","for",61,64],["G2532","for",61,64],["G1989","I have written a letter",65,88],["G5213","unto you",89,97],["G1223","in",98,100],["G1024","few words",101,110]]},"13:23":{"text":"Know ye that our brother Timothy is set at liberty; with whom, if he come shortly, I will see you.","words":[["G1097","Know ye",0,7],["G0080","that our brother",8,24],["G5095","Timothy",25,32],["G0630","is set at liberty",33,50],["G3326","with",52,56],["G3739","whom",57,61],["G1437","if",63,65],["G2064","he come",66,73],["G5032","shortly",74,81],["G3700","I will see",83,93],["G5209","you",94,97]]},"13:24":{"text":"Salute all them that have the rule over you, and all the saints. They of Italy salute you.","words":[["G0782","Salute",0,6],["G3956","all",7,10],["G2233","them that have the rule",11,34],["G5216","over you",35,43],["G2532","and",45,48],["G3956","all",49,52],["G0040","the saints",53,63],["G0575","They of",65,72],["G2482","Italy",73,78],["G0782","salute",79,85],["G5209","you",86,89]]},"13:25":{"text":"Grace be with you all. Amen.","words":[["G5485","Grace",0,5],["G3326","be with",6,13],["G5216","you",14,17],["G3956","all",18,21],["G0281","Amen",23,27]]}}};
